//! Audio pipeline benchmarks: mixer throughput, DSP chain, metering.

use std::collections::HashMap;

use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};
use dhvani::buffer::AudioBuffer;

use aethersafta::audio::{AudioMixer, AudioMixerConfig, AudioSourceConfig};

fn test_buffer(value: f32, frames: usize) -> AudioBuffer {
    AudioBuffer::from_interleaved(vec![value; frames * 2], 2, 48000).unwrap()
}

// ---------------------------------------------------------------------------
// Mixer throughput
// ---------------------------------------------------------------------------

fn bench_mix_single_source(c: &mut Criterion) {
    let mut group = c.benchmark_group("mix_single_source");

    for &frames in &[256, 1024, 4096] {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Source"));

        group.bench_with_input(BenchmarkId::new("frames", frames), &frames, |b, &frames| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, frames));
                mixer.mix(&mut buffers)
            })
        });
    }
    group.finish();
}

fn bench_mix_multi_source(c: &mut Criterion) {
    let mut group = c.benchmark_group("mix_multi_source");

    for &n_sources in &[2, 4, 8, 16] {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let ids: Vec<_> = (0..n_sources)
            .map(|i| mixer.add_source(AudioSourceConfig::new(format!("Src-{i}"))))
            .collect();

        group.bench_with_input(
            BenchmarkId::new("1024_frames", format!("{n_sources}_sources")),
            &(),
            |b, _| {
                b.iter(|| {
                    let mut buffers = HashMap::new();
                    for &id in &ids {
                        buffers.insert(id, test_buffer(0.3, 1024));
                    }
                    mixer.mix(&mut buffers)
                })
            },
        );
    }
    group.finish();
}

// ---------------------------------------------------------------------------
// DSP chain
// ---------------------------------------------------------------------------

fn bench_mix_with_dsp(c: &mut Criterion) {
    let mut group = c.benchmark_group("mix_with_dsp");

    // Baseline: no DSP
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Plain"));

        group.bench_function("no_dsp", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // EQ only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("EQ"));
        mixer.set_source_eq(
            id,
            vec![
                dhvani::dsp::EqBandConfig {
                    band_type: dhvani::dsp::BandType::HighPass,
                    freq_hz: 80.0,
                    gain_db: 0.0,
                    q: 0.707,
                    enabled: true,
                },
                dhvani::dsp::EqBandConfig {
                    band_type: dhvani::dsp::BandType::Peaking,
                    freq_hz: 3000.0,
                    gain_db: 3.0,
                    q: 1.0,
                    enabled: true,
                },
            ],
        );

        group.bench_function("eq_2band", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Compressor only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Comp"));
        mixer.set_source_compressor(
            id,
            dhvani::dsp::CompressorParams {
                threshold_db: -20.0,
                ratio: 4.0,
                attack_ms: 5.0,
                release_ms: 50.0,
                makeup_gain_db: 0.0,
                knee_db: 6.0,
                mix: 1.0,
            },
        );

        group.bench_function("compressor", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.8, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Full chain: EQ + compressor + limiter
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: true,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Full"));
        mixer.set_source_eq(
            id,
            vec![dhvani::dsp::EqBandConfig {
                band_type: dhvani::dsp::BandType::HighPass,
                freq_hz: 80.0,
                gain_db: 0.0,
                q: 0.707,
                enabled: true,
            }],
        );
        mixer.set_source_compressor(
            id,
            dhvani::dsp::CompressorParams {
                threshold_db: -18.0,
                ratio: 3.0,
                attack_ms: 10.0,
                release_ms: 100.0,
                makeup_gain_db: 3.0,
                knee_db: 6.0,
                mix: 1.0,
            },
        );

        group.bench_function("full_chain_eq_comp_limiter", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.7, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Noise gate only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Gate"));
        mixer.set_source_noise_gate(id, 0.01);

        group.bench_function("noise_gate", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // De-esser only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("DeEss"));
        mixer.set_source_deesser(
            id,
            dhvani::dsp::DeEsserParams {
                freq_hz: 6000.0,
                threshold_db: -20.0,
                reduction_db: 6.0,
                q: 1.0,
            },
        );

        group.bench_function("deesser", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Graphic EQ only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("GEQ"));
        mixer.set_source_graphic_eq(
            id,
            dhvani::dsp::GraphicEqSettings {
                enabled: true,
                bands: [3.0, 1.0, 0.0, -1.0, 0.0, 2.0, 0.0, -2.0, 1.0, -3.0],
            },
        );

        group.bench_function("graphic_eq_10band", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Reverb only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Rev"));
        mixer.set_source_reverb(
            id,
            dhvani::dsp::ReverbParams {
                room_size: 0.8,
                damping: 0.5,
                mix: 0.3,
            },
        );

        group.bench_function("reverb", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Delay only
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Dly"));
        mixer.set_source_delay(id, 50.0, 0.3, 0.5);

        group.bench_function("delay", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    // Full expanded chain: gate + EQ + comp + deesser + delay + reverb + limiter
    {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: true,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("AllFx"));
        mixer.set_source_noise_gate(id, 0.01);
        mixer.set_source_eq(
            id,
            vec![dhvani::dsp::EqBandConfig {
                band_type: dhvani::dsp::BandType::HighPass,
                freq_hz: 80.0,
                gain_db: 0.0,
                q: 0.707,
                enabled: true,
            }],
        );
        mixer.set_source_compressor(
            id,
            dhvani::dsp::CompressorParams {
                threshold_db: -20.0,
                ratio: 4.0,
                attack_ms: 5.0,
                release_ms: 50.0,
                makeup_gain_db: 0.0,
                knee_db: 6.0,
                mix: 1.0,
            },
        );
        mixer.set_source_deesser(
            id,
            dhvani::dsp::DeEsserParams {
                freq_hz: 6000.0,
                threshold_db: -20.0,
                reduction_db: 6.0,
                q: 1.0,
            },
        );
        mixer.set_source_delay(id, 10.0, 0.2, 0.3);
        mixer.set_source_reverb(
            id,
            dhvani::dsp::ReverbParams {
                room_size: 0.5,
                damping: 0.5,
                mix: 0.2,
            },
        );

        group.bench_function("full_chain_all_effects", |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(0.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }

    group.finish();
}

// ---------------------------------------------------------------------------
// Master limiter
// ---------------------------------------------------------------------------

fn bench_master_limiter(c: &mut Criterion) {
    let mut group = c.benchmark_group("master_limiter");

    for &enabled in &[false, true] {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: enabled,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Src"));

        let label = if enabled { "enabled" } else { "disabled" };
        group.bench_function(label, |b| {
            b.iter(|| {
                let mut buffers = HashMap::new();
                buffers.insert(id, test_buffer(1.5, 1024));
                mixer.mix(&mut buffers)
            })
        });
    }
    group.finish();
}

// ---------------------------------------------------------------------------
// Metering overhead
// ---------------------------------------------------------------------------

fn bench_metering(c: &mut Criterion) {
    let mut mixer = AudioMixer::new(AudioMixerConfig {
        master_limiter: false,
        ..Default::default()
    });
    let id = mixer.add_source(AudioSourceConfig::new("Metered"));

    c.bench_function("mix_1024_with_metering", |b| {
        b.iter(|| {
            let mut buffers = HashMap::new();
            buffers.insert(id, test_buffer(0.5, 1024));
            mixer.mix(&mut buffers);
            // Read meters (simulates UI polling)
            let _ = mixer.source_peak_db(id, 0);
            let _ = mixer.source_rms_db(id, 0);
            let _ = mixer.master_peak_db(0);
            let _ = mixer.master_rms_db(0);
            let _ = mixer.master_lufs();
        })
    });
}

criterion_group!(
    benches,
    bench_mix_single_source,
    bench_mix_multi_source,
    bench_mix_with_dsp,
    bench_master_limiter,
    bench_metering,
);
criterion_main!(benches);

use std::collections::HashMap;

use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};

use aethersafta::scene::compositor::Compositor;
use aethersafta::scene::{Layer, LayerContent, SceneGraph};
use aethersafta::source::RawFrame;

// ---------------------------------------------------------------------------
// Scene graph benchmarks
// ---------------------------------------------------------------------------

fn bench_scene_add_layers(c: &mut Criterion) {
    c.bench_function("scene_add_100_layers", |b| {
        b.iter(|| {
            let mut scene = SceneGraph::new(1920, 1080, 30);
            for i in 0..100 {
                let mut layer = Layer::new(
                    format!("layer-{i}"),
                    LayerContent::ColorFill {
                        color: [255, 0, 0, 255],
                    },
                );
                layer.z_index = i;
                scene.add_layer(layer);
            }
            scene
        })
    });
}

fn bench_visible_layers(c: &mut Criterion) {
    let mut scene = SceneGraph::new(1920, 1080, 30);
    for i in 0..50 {
        let mut layer = Layer::new(
            format!("layer-{i}"),
            LayerContent::ColorFill {
                color: [0, 0, 0, 255],
            },
        );
        layer.visible = i % 3 != 0;
        layer.z_index = i;
        scene.add_layer(layer);
    }

    c.bench_function("visible_layers_50", |b| b.iter(|| scene.visible_layers()));
}

// ---------------------------------------------------------------------------
// Compositor benchmarks
// ---------------------------------------------------------------------------

fn make_argb_frame(width: u32, height: u32, val: u8) -> RawFrame {
    RawFrame {
        data: vec![val; (width * height * 4) as usize],
        format: aethersafta::source::PixelFormat::Argb8888,
        width,
        height,
        pts_us: 0,
    }
}

fn bench_composite_color_fill(c: &mut Criterion) {
    let mut group = c.benchmark_group("composite_color_fill");
    for &(w, h, label) in &[(1920, 1080, "1080p"), (3840, 2160, "4K")] {
        let comp = Compositor::new(w, h);
        let mut scene = SceneGraph::new(w, h, 30);
        scene.add_layer(Layer::new(
            "bg",
            LayerContent::ColorFill {
                color: [0, 0, 128, 255],
            },
        ));
        let frames = HashMap::new();

        group.bench_with_input(BenchmarkId::new("single_layer", label), &(), |b, _| {
            b.iter(|| comp.compose(&scene, &frames, 0))
        });
    }
    group.finish();
}

fn bench_composite_source_layers(c: &mut Criterion) {
    let mut group = c.benchmark_group("composite_source_layers");

    for &n_layers in &[1, 3, 5] {
        let w = 1920;
        let h = 1080;
        let comp = Compositor::new(w, h);
        let mut scene = SceneGraph::new(w, h, 30);
        let mut frames = HashMap::new();

        for i in 0..n_layers {
            let src_id = uuid::Uuid::new_v4();
            let mut layer = Layer::new(
                format!("src-{i}"),
                LayerContent::Source { source_id: src_id },
            );
            layer.z_index = i;
            layer.opacity = 0.8;
            scene.add_layer(layer);

            // Find the layer ID that was just added (last in z-order)
            let layer_id = scene
                .layers()
                .iter()
                .find(|l| l.name == format!("src-{i}"))
                .unwrap()
                .id;
            frames.insert(layer_id, make_argb_frame(w, h, 128));
        }

        group.bench_with_input(
            BenchmarkId::new("1080p", format!("{n_layers}_layers")),
            &(),
            |b, _| b.iter(|| comp.compose(&scene, &frames, 0)),
        );
    }
    group.finish();
}

fn bench_composite_scaled(c: &mut Criterion) {
    let w = 1920;
    let h = 1080;
    let comp = Compositor::new(w, h);
    let mut scene = SceneGraph::new(w, h, 30);

    // 640x480 source scaled up to fill 1920x1080
    let mut layer = Layer::new(
        "scaled",
        LayerContent::Source {
            source_id: uuid::Uuid::nil(),
        },
    );
    layer.size = Some((w, h));
    let layer_id = layer.id;
    scene.add_layer(layer);

    let mut frames = HashMap::new();
    frames.insert(layer_id, make_argb_frame(640, 480, 200));

    c.bench_function("composite_scaled_480p_to_1080p", |b| {
        b.iter(|| comp.compose(&scene, &frames, 0))
    });
}

// ---------------------------------------------------------------------------
// Color conversion benchmark
// ---------------------------------------------------------------------------

fn bench_composite_multi_scaled(c: &mut Criterion) {
    let mut group = c.benchmark_group("composite_multi_scaled");

    for &n_layers in &[2, 4] {
        let w = 1920;
        let h = 1080;
        let comp = Compositor::new(w, h);
        let mut scene = SceneGraph::new(w, h, 30);
        let mut frames = HashMap::new();

        for i in 0..n_layers {
            let mut layer = Layer::new(
                format!("scaled-{i}"),
                LayerContent::Source {
                    source_id: uuid::Uuid::new_v4(),
                },
            );
            layer.z_index = i;
            layer.opacity = 0.7;
            // Each layer is 640x480 scaled to 960x540
            layer.size = Some((960, 540));
            layer.position = (i * 100, i * 80);
            let lid = layer.id;
            scene.add_layer(layer);
            frames.insert(lid, make_argb_frame(640, 480, 128 + i as u8 * 30));
        }

        group.bench_with_input(
            BenchmarkId::new("1080p_bicubic", format!("{n_layers}_layers")),
            &(),
            |b, _| b.iter(|| comp.compose(&scene, &frames, 0)),
        );
    }
    group.finish();
}

fn bench_composite_4k(c: &mut Criterion) {
    let w = 3840;
    let h = 2160;
    let comp = Compositor::new(w, h);
    let mut scene = SceneGraph::new(w, h, 30);

    // Background fill
    let mut bg = Layer::new(
        "bg",
        LayerContent::ColorFill {
            color: [30, 30, 30, 255],
        },
    );
    bg.z_index = 0;
    scene.add_layer(bg);

    // Single 4K source layer
    let mut layer = Layer::new(
        "4k-src",
        LayerContent::Source {
            source_id: uuid::Uuid::nil(),
        },
    );
    layer.z_index = 1;
    layer.opacity = 0.9;
    let lid = layer.id;
    scene.add_layer(layer);

    let mut frames = HashMap::new();
    frames.insert(lid, make_argb_frame(w, h, 180));

    c.bench_function("composite_4k_bg_plus_source", |b| {
        b.iter(|| comp.compose(&scene, &frames, 0))
    });
}

criterion_group!(
    benches,
    bench_scene_add_layers,
    bench_visible_layers,
    bench_composite_color_fill,
    bench_composite_source_layers,
    bench_composite_scaled,
    bench_composite_multi_scaled,
    bench_composite_4k,
);
criterion_main!(benches);

//! Color conversion and format interchange benchmarks.

use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};

use aethersafta::encode::{argb_to_nv12, argb_to_yuv420p, nv12_to_argb};

fn make_argb(width: u32, height: u32) -> Vec<u8> {
    let size = (width * height * 4) as usize;
    let mut data = vec![0u8; size];
    for (i, chunk) in data.chunks_exact_mut(4).enumerate() {
        chunk[0] = 255; // A
        chunk[1] = (i % 256) as u8; // R
        chunk[2] = ((i * 3) % 256) as u8; // G
        chunk[3] = ((i * 7) % 256) as u8; // B
    }
    data
}

fn make_nv12(width: u32, height: u32) -> Vec<u8> {
    let y_size = (width * height) as usize;
    let uv_size = (width * (height / 2)) as usize;
    vec![128u8; y_size + uv_size]
}

// ---------------------------------------------------------------------------
// ARGB → YUV420p (BT.709)
// ---------------------------------------------------------------------------

fn bench_argb_to_yuv420p(c: &mut Criterion) {
    let mut group = c.benchmark_group("argb_to_yuv420p_bt709");
    for &(w, h, label) in &[
        (640, 480, "480p"),
        (1280, 720, "720p"),
        (1920, 1080, "1080p"),
        (3840, 2160, "4K"),
    ] {
        let argb = make_argb(w, h);
        group.bench_with_input(BenchmarkId::new("convert", label), &(), |b, _| {
            b.iter(|| argb_to_yuv420p(&argb, w, h))
        });
    }
    group.finish();
}

// ---------------------------------------------------------------------------
// ARGB → NV12
// ---------------------------------------------------------------------------

fn bench_argb_to_nv12(c: &mut Criterion) {
    let mut group = c.benchmark_group("argb_to_nv12");
    for &(w, h, label) in &[
        (640, 480, "480p"),
        (1280, 720, "720p"),
        (1920, 1080, "1080p"),
        (3840, 2160, "4K"),
    ] {
        let argb = make_argb(w, h);
        group.bench_with_input(BenchmarkId::new("convert", label), &(), |b, _| {
            b.iter(|| argb_to_nv12(&argb, w, h))
        });
    }
    group.finish();
}

// ---------------------------------------------------------------------------
// NV12 → ARGB
// ---------------------------------------------------------------------------

fn bench_nv12_to_argb(c: &mut Criterion) {
    let mut group = c.benchmark_group("nv12_to_argb");
    for &(w, h, label) in &[
        (640, 480, "480p"),
        (1280, 720, "720p"),
        (1920, 1080, "1080p"),
        (3840, 2160, "4K"),
    ] {
        let nv12 = make_nv12(w, h);
        group.bench_with_input(BenchmarkId::new("convert", label), &(), |b, _| {
            b.iter(|| nv12_to_argb(&nv12, w, h))
        });
    }
    group.finish();
}

// ---------------------------------------------------------------------------
// Roundtrip: ARGB → NV12 → ARGB
// ---------------------------------------------------------------------------

fn bench_nv12_roundtrip(c: &mut Criterion) {
    let mut group = c.benchmark_group("nv12_roundtrip");
    for &(w, h, label) in &[(640, 480, "480p"), (1920, 1080, "1080p")] {
        let argb = make_argb(w, h);
        group.bench_with_input(BenchmarkId::new("argb_nv12_argb", label), &(), |b, _| {
            b.iter(|| {
                let nv12 = argb_to_nv12(&argb, w, h);
                nv12_to_argb(&nv12, w, h)
            })
        });
    }
    group.finish();
}

criterion_group!(
    benches,
    bench_argb_to_yuv420p,
    bench_argb_to_nv12,
    bench_nv12_to_argb,
    bench_nv12_roundtrip,
);
criterion_main!(benches);

//! Encoding benchmarks — requires `openh264-enc` feature.
//!
//! Run with: cargo bench --bench encode --features openh264-enc

#[cfg(feature = "openh264-enc")]
use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};

#[cfg(feature = "openh264-enc")]
fn make_argb_frame(width: u32, height: u32, pts_us: u64) -> aethersafta::source::RawFrame {
    let size = (width * height * 4) as usize;
    let mut data = vec![0u8; size];
    for (i, chunk) in data.chunks_exact_mut(4).enumerate() {
        let x = (i as u32) % width;
        let y = (i as u32) / width;
        chunk[0] = 255; // A
        chunk[1] = (x % 256) as u8; // R
        chunk[2] = (y % 256) as u8; // G
        chunk[3] = ((x + y) % 256) as u8; // B
    }
    aethersafta::source::RawFrame {
        data,
        format: aethersafta::source::PixelFormat::Argb8888,
        width,
        height,
        pts_us,
    }
}

#[cfg(feature = "openh264-enc")]
fn bench_encode_single_frame(c: &mut Criterion) {
    use aethersafta::encode::{EncodePipeline, EncoderConfig};

    let mut group = c.benchmark_group("encode_h264_single_frame");

