//! Scene graph compositing with latency tracking.
//!
//! Creates a 1280x720 scene with a solid blue background and a synthetic
//! gradient overlay, composes 30 frames, and reports per-frame timing
//! via LatencyBudget.

use std::collections::HashMap;
use std::time::{Duration, Instant};

use aethersafta::{
    Compositor, FrameClock, LatencyBudget, Layer, SceneGraph,
    scene::LayerContent,
    source::Source,
    source::synthetic::{Pattern, SyntheticSource},
};

fn main() -> anyhow::Result<()> {
    let (width, height, fps) = (1280, 720, 30);

    // -- scene ---------------------------------------------------------------
    let mut scene = SceneGraph::new(width, height, fps);

    // Background: solid dark blue
    let bg = Layer::new(
        "background",
        LayerContent::ColorFill {
            color: [30, 40, 80, 255],
        },
    );
    scene.add_layer(bg);

    // Overlay: synthetic gradient bound to a Source layer
    let gradient = SyntheticSource::new("gradient", width, height, fps, Pattern::Gradient);
    let src_id = gradient.id();
    let mut overlay = Layer::new("gradient", LayerContent::Source { source_id: src_id });
    overlay.opacity = 0.6;
    overlay.z_index = 1;
    let overlay_id = scene.add_layer(overlay);

    println!("{scene}");

    // -- compose loop --------------------------------------------------------
    let compositor = Compositor::new(width, height);
    let mut clock = FrameClock::new(fps);
    let mut budget = LatencyBudget::new(Duration::from_secs_f64(1.0 / fps as f64));

    for _ in 0..30 {
        let pts = clock.current_pts_us();

        // Capture
        let t0 = Instant::now();
        let mut source_frames = HashMap::new();
        if let Some(frame) = gradient.capture_frame()? {
            source_frames.insert(overlay_id, frame);
        }
        budget.capture_us = t0.elapsed().as_micros() as u64;

        // Composite
        let t1 = Instant::now();
        let _composited = compositor.compose(&scene, &source_frames, pts);
        budget.composite_us = t1.elapsed().as_micros() as u64;

        clock.tick();

        if clock.frame_count().is_multiple_of(10) {
            let ok = if budget.within_budget() { "OK" } else { "OVER" };
            println!(
                "frame {:>3}  pts={:>8}us  capture={:>5}us  composite={:>5}us  headroom={:>6}us  [{}]",
                clock.frame_count(),
                pts,
                budget.capture_us,
                budget.composite_us,
                budget.headroom_us(),
                ok,
            );
        }
    }

    println!(
        "done: {} frames, {} valid",
        clock.frame_count(),
        if !clock.is_behind() {
            "on time"
        } else {
            "behind schedule"
        },
    );
    Ok(())
}

//! Encode pipeline: compose synthetic frames and write H.264 to a file.
//!
//! Generates 90 frames (3 seconds at 30 fps) from a checkerboard source,
//! composites them, encodes to H.264, and writes raw NAL units to disk.
//! Requires the `openh264-enc` or `vaapi` feature to be enabled.

use std::collections::HashMap;
use std::time::Instant;

use aethersafta::{
    Compositor, EncodePipeline, EncoderConfig, FrameClock, Layer, SceneGraph,
    output::{OutputSink, file::FileOutput},
    scene::LayerContent,
    source::Source,
    source::synthetic::{Pattern, SyntheticSource},
};

fn main() -> anyhow::Result<()> {
    let (width, height, fps) = (640, 480, 30);
    let total_frames: u64 = 90;
    let out_path = "output.h264";

    // -- scene ---------------------------------------------------------------
    let mut scene = SceneGraph::new(width, height, fps);
    let checker = SyntheticSource::new("checker", width, height, fps, Pattern::Checkerboard(32));
    let src_id = checker.id();
    let layer = Layer::new("checker", LayerContent::Source { source_id: src_id });
    let layer_id = scene.add_layer(layer);

    // -- pipeline ------------------------------------------------------------
    let compositor = Compositor::new(width, height);
    let config = EncoderConfig {
        bitrate_kbps: 2000,
        keyframe_interval: 30,
        ..EncoderConfig::default()
    };
    let mut encoder = EncodePipeline::new(config);
    encoder.init(width, height, fps)?;
    println!("encoder backend: {}", encoder.backend());

    let mut output = FileOutput::create(out_path)?;
    let mut clock = FrameClock::new(fps);
    let start = Instant::now();

    // -- frame loop ----------------------------------------------------------
    for _ in 0..total_frames {
        let pts = clock.current_pts_us();

        let mut frames = HashMap::new();
        if let Some(f) = checker.capture_frame()? {
            frames.insert(layer_id, f);
        }

        let composited = compositor.compose(&scene, &frames, pts);
        let packet = encoder.encode_frame(&composited)?;
        output.write_packet(&packet)?;

        clock.tick();
    }

    output.close()?;
    let elapsed = start.elapsed();

    println!(
        "wrote {} frames to {out_path} ({} packets, {} bytes)",
        clock.frame_count(),
        output.packets_written(),
        output.bytes_written(),
    );
    println!(
        "wall time: {:.2}s  ({:.1} fps)",
        elapsed.as_secs_f64(),
        clock.frame_count() as f64 / elapsed.as_secs_f64(),
    );
    Ok(())
}

//! Mini recording session: encode 60 frames to a file.
//!
//! Accepts an optional image path as the first CLI argument. If provided,
//! the image is loaded as a source layer; otherwise a synthetic solid
//! color source is used as a fallback. Prints per-second frame timing.

use std::collections::HashMap;
use std::time::Instant;

use aethersafta::{
    Compositor, EncodePipeline, EncoderConfig, FrameClock, Layer, SceneGraph,
    output::{OutputSink, file::FileOutput},
    scene::LayerContent,
    source::Source,
    source::image::ImageSource,
    source::synthetic::{Pattern, SyntheticSource},
};

fn main() -> anyhow::Result<()> {
    let (width, height, fps) = (1280, 720, 30);
    let total_frames: u64 = 60;
    let out_path = "recording.h264";

    let args: Vec<String> = std::env::args().collect();

    // -- scene ---------------------------------------------------------------
    let mut scene = SceneGraph::new(width, height, fps);

    // Background
    let mut bg = Layer::new(
        "bg",
        LayerContent::ColorFill {
            color: [20, 20, 20, 255],
        },
    );
    bg.z_index = 0;
    scene.add_layer(bg);

    // Content layer: image from CLI arg, or synthetic fallback
    let source: Box<dyn Source> = if let Some(path) = args.get(1) {
        println!("loading image: {path}");
        Box::new(ImageSource::open(path)?)
    } else {
        println!("no image path given, using synthetic source");
        Box::new(SyntheticSource::new(
            "solid",
            width,
            height,
            fps,
            Pattern::Solid([255, 100, 60, 200]),
        ))
    };

    let mut content = Layer::new(
        source.name(),
        LayerContent::Source {
            source_id: source.id(),
        },
    );
    content.z_index = 1;
    content.size = Some((width, height));
    let content_id = scene.add_layer(content);

    // -- pipeline ------------------------------------------------------------
    let compositor = Compositor::new(width, height);
    let mut encoder = EncodePipeline::new(EncoderConfig {
        bitrate_kbps: 4000,
        keyframe_interval: 30,
        ..EncoderConfig::default()
    });
    encoder.init(width, height, fps)?;

    let mut output = FileOutput::create(out_path)?;
    let mut clock = FrameClock::new(fps);
    let start = Instant::now();

    // -- record loop ---------------------------------------------------------
    for _ in 0..total_frames {
        let pts = clock.current_pts_us();

        let mut frames = HashMap::new();
        if let Some(f) = source.capture_frame()? {
            frames.insert(content_id, f);
        }

        let composited = compositor.compose(&scene, &frames, pts);
        let packet = encoder.encode_frame(&composited)?;
        output.write_packet(&packet)?;

        clock.tick();

        // Print timing every second of video time
        if clock.frame_count().is_multiple_of(fps as u64) {
            let wall = start.elapsed().as_secs_f64();
            let video = clock.frame_count() as f64 / fps as f64;
            let ratio = video / wall;
            println!(
                "  t={:.1}s  frames={}  wall={:.2}s  speed={:.1}x",
                video,
                clock.frame_count(),
                wall,
                ratio,
            );
        }
    }

    output.close()?;
    println!(
        "recorded {} frames to {out_path} ({} bytes)",
        clock.frame_count(),
        output.bytes_written(),
    );
    Ok(())
}

