//! Multi-source audio capture manager.
//!
//! Manages concurrent [`dhvani::capture::PwCapture`] instances for capturing
//! audio from multiple PipeWire devices simultaneously (system audio, mic, per-app).

use std::collections::HashMap;

#[cfg(feature = "pipewire")]
use dhvani::capture::{CaptureConfig, CaptureEvent, PwCapture};

use super::{AudioSourceConfig, AudioSourceId};

/// State for a single capture source.
#[cfg(feature = "pipewire")]
struct CaptureSource {
    capture: PwCapture,
    config: AudioSourceConfig,
    running: bool,
}

/// Manages concurrent audio capture from multiple PipeWire devices.
///
/// Each source gets its own [`PwCapture`] instance with independent
/// sample rates and buffer sizes. Buffers are collected per-source
/// and fed into the [`AudioMixer`](super::AudioMixer) for mixing.
#[cfg(feature = "pipewire")]
pub struct AudioCaptureManager {
    sources: HashMap<AudioSourceId, CaptureSource>,
    default_sample_rate: u32,
    default_buffer_frames: u32,
}

#[cfg(feature = "pipewire")]
impl AudioCaptureManager {
    /// Create a new capture manager.
    #[must_use]
    pub fn new() -> Self {
        Self {
            sources: HashMap::new(),
            default_sample_rate: 48000,
            default_buffer_frames: 1024,
        }
    }

    /// Create with custom defaults.
    #[must_use]
    pub fn with_defaults(sample_rate: u32, buffer_frames: u32) -> Self {
        Self {
            sources: HashMap::new(),
            default_sample_rate: sample_rate,
            default_buffer_frames: buffer_frames,
        }
    }

    /// Add and start capturing from a new audio source.
    ///
    /// Returns the source ID on success.
    pub fn add_source(
        &mut self,
        id: AudioSourceId,
        config: AudioSourceConfig,
    ) -> anyhow::Result<()> {
        let capture_config = CaptureConfig {
            device_id: config.device_id,
            sample_rate: self.default_sample_rate,
            channels: 2,
            buffer_frames: self.default_buffer_frames,
        };

        let mut capture = PwCapture::new(capture_config)?;
        capture.start()?;

        self.sources.insert(
            id,
            CaptureSource {
                capture,
                config,
                running: true,
            },
        );

        Ok(())
    }

    /// Remove a capture source. Stops capture automatically.
    pub fn remove_source(&mut self, id: AudioSourceId) -> bool {
        if let Some(mut source) = self.sources.remove(&id) {
            if source.running {
                let _ = source.capture.stop();
            }
            true
        } else {
            false
        }
    }

    /// Collect all available audio buffers from all sources.
    ///
    /// Returns a map of source ID → latest audio buffer, suitable for
    /// passing directly to [`AudioMixer::mix`](super::AudioMixer::mix).
    #[must_use]
    pub fn drain_buffers(&self) -> HashMap<AudioSourceId, dhvani::buffer::AudioBuffer> {
        let mut buffers = HashMap::new();

        for (&id, source) in &self.sources {
            if !source.running {
                continue;
            }
            // Drain all pending buffers, keep only the latest
            let mut latest = None;
            while let Some(buf) = source.capture.try_recv() {
                latest = Some(buf);
            }
            if let Some(buf) = latest {
                buffers.insert(id, buf);
            }
        }

        buffers
    }

    /// Collect hot-plug events from all sources.
    #[must_use]
    pub fn drain_events(&self) -> Vec<(AudioSourceId, CaptureEvent)> {
        let mut events = Vec::new();
        for (&id, source) in &self.sources {
            while let Some(event) = source.capture.try_recv_event() {
                events.push((id, event));
            }
        }
        events
    }

    /// Number of active capture sources.
    #[must_use]
    pub fn source_count(&self) -> usize {
        self.sources.len()
    }

    /// Whether a specific source is currently capturing.
    #[must_use]
    pub fn is_running(&self, id: AudioSourceId) -> bool {
        self.sources
            .get(&id)
            .is_some_and(|s| s.running && s.capture.is_running())
    }

    /// Stop all captures.
    pub fn stop_all(&mut self) {
        for source in self.sources.values_mut() {
            if source.running {
                let _ = source.capture.stop();
                source.running = false;
            }
        }
    }

    /// Get the config for a source.
    #[must_use]
    pub fn get_config(&self, id: AudioSourceId) -> Option<&AudioSourceConfig> {
        self.sources.get(&id).map(|s| &s.config)
    }
}

#[cfg(feature = "pipewire")]
impl Default for AudioCaptureManager {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(feature = "pipewire")]
impl Drop for AudioCaptureManager {
    fn drop(&mut self) {
        self.stop_all();
    }
}

#[cfg(test)]
mod tests {
    #[test]
    fn capture_manager_requires_pipewire_feature() {
        // Compile-time check: AudioCaptureManager only available with pipewire feature.
        // This test just verifies the module compiles cleanly.
    }
}

//! Graph-based audio pipeline using [`dhvani::graph`].
//!
//! Builds an audio processing graph where each source flows through
//! per-source DSP nodes, into a mixer node, then through master DSP
//! to the output. The graph is compiled into an [`ExecutionPlan`] and
//! processed by a [`GraphProcessor`] for real-time safe execution.
//!
//! ```text
//! Source 1 → [Gain] → [EQ] → [Compressor] → [Pan] ──┐
//! Source 2 → [Gain] → [EQ] → [Compressor] → [Pan] ──┤
//!                                                     ├→ [Mixer] → [Limiter] → [Meter] → Output
//! Source N → [Gain] → [EQ] → [Compressor] → [Pan] ──┘
//! ```

use std::collections::HashMap;

use dhvani::buffer::AudioBuffer;
use dhvani::graph::{AudioNode, Graph, GraphProcessor, NodeId};

use super::{AudioMixerConfig, AudioSourceId};

// --- Audio graph nodes ---

/// Input node: injects a captured audio buffer into the graph.
#[allow(dead_code)]
pub(crate) struct InputNode {
    buffer: Option<AudioBuffer>,
    channels: u32,
    sample_rate: u32,
}

#[allow(dead_code)]
impl InputNode {
    pub fn new(channels: u32, sample_rate: u32) -> Self {
        Self {
            buffer: None,
            channels,
            sample_rate,
        }
    }

    /// Set the buffer to be emitted on the next process cycle.
    pub fn set_buffer(&mut self, buf: AudioBuffer) {
        self.buffer = Some(buf);
    }
}

impl AudioNode for InputNode {
    fn name(&self) -> &str {
        "input"
    }

    fn num_inputs(&self) -> usize {
        0
    }

    fn num_outputs(&self) -> usize {
        1
    }

    #[inline]
    fn process(&mut self, _inputs: &[&AudioBuffer], output: &mut AudioBuffer) {
        if let Some(buf) = self.buffer.take() {
            *output = buf;
        } else {
            *output = AudioBuffer::silence(self.channels, 1024, self.sample_rate);
        }
    }
}

/// Gain node: applies a linear gain multiplier.
#[allow(dead_code)]
pub(crate) struct GainNode {
    gain: f32,
}

#[allow(dead_code)]
impl GainNode {
    pub fn new(gain: f32) -> Self {
        Self { gain }
    }

    pub fn set_gain(&mut self, gain: f32) {
        self.gain = gain;
    }
}

impl AudioNode for GainNode {
    fn name(&self) -> &str {
        "gain"
    }

    fn num_inputs(&self) -> usize {
        1
    }

    fn num_outputs(&self) -> usize {
        1
    }

    #[inline]
    fn process(&mut self, inputs: &[&AudioBuffer], output: &mut AudioBuffer) {
        if let Some(input) = inputs.first() {
            *output = (*input).clone();
            if (self.gain - 1.0).abs() > f32::EPSILON {
                output.apply_gain(self.gain);
            }
        }
    }
}

/// Mixer node: sums all input buffers.
pub(crate) struct MixerNode;

impl AudioNode for MixerNode {
    fn name(&self) -> &str {
        "mixer"
    }

    fn num_inputs(&self) -> usize {
        // Accept any number of inputs; the graph wires the actual connections.
        usize::MAX
    }

    fn num_outputs(&self) -> usize {
        1
    }

    #[inline]
    fn process(&mut self, inputs: &[&AudioBuffer], output: &mut AudioBuffer) {
        if inputs.is_empty() {
            return;
        }
        if inputs.len() == 1 {
            *output = inputs[0].clone();
            return;
        }
        if let Ok(mixed) = dhvani::buffer::mix(inputs) {
            *output = mixed;
        }
    }
}

/// DSP chain node: applies EQ, compressor, and panner in sequence.
#[allow(dead_code)]
pub(crate) struct DspChainNode {
    eq: Option<dhvani::dsp::ParametricEq>,
    compressor: Option<dhvani::dsp::Compressor>,
    panner: dhvani::dsp::StereoPanner,
}

#[allow(dead_code)]
impl DspChainNode {
    pub fn new(pan: f32) -> Self {
        Self {
            eq: None,
            compressor: None,
            panner: dhvani::dsp::StereoPanner::new(pan),
        }
    }

    pub fn set_eq(&mut self, eq: dhvani::dsp::ParametricEq) {
        self.eq = Some(eq);
    }

    pub fn set_compressor(&mut self, comp: dhvani::dsp::Compressor) {
        self.compressor = Some(comp);
    }

    pub fn set_pan(&mut self, pan: f32) {
        self.panner.set_pan(pan);
    }
}

impl AudioNode for DspChainNode {
    fn name(&self) -> &str {
        "dsp_chain"
    }

    fn num_inputs(&self) -> usize {
        1
    }

    fn num_outputs(&self) -> usize {
        1
    }

    #[inline]
    fn process(&mut self, inputs: &[&AudioBuffer], output: &mut AudioBuffer) {
        if let Some(input) = inputs.first() {
            *output = (*input).clone();
            if let Some(eq) = &mut self.eq {
                eq.process(output);
            }
            if let Some(comp) = &mut self.compressor {
                comp.process(output);
            }
            self.panner.process(output);
            for sample in output.samples_mut() {
                *sample = dhvani::dsp::sanitize_sample(*sample);
            }
        }
    }
}

/// Master bus node: limiter + metering.
#[allow(dead_code)]
pub(crate) struct MasterNode {
    limiter: Option<dhvani::dsp::EnvelopeLimiter>,
    meter: dhvani::meter::LevelMeter,
}

#[allow(dead_code)]
impl MasterNode {
    pub fn new(config: &AudioMixerConfig) -> Self {
        let limiter = if config.master_limiter {
            dhvani::dsp::EnvelopeLimiter::new(
                dhvani::dsp::LimiterParams::default(),
                config.sample_rate,
            )
            .ok()
        } else {
            None
        };

        Self {
            limiter,
            meter: dhvani::meter::LevelMeter::new(
                config.channels as usize,
                config.sample_rate as f32,
            ),
        }
    }

    pub fn peak_db(&self, channel: usize) -> f32 {
        self.meter.peak_db(channel)
    }

    pub fn rms_db(&self, channel: usize) -> f32 {
        self.meter.rms_db(channel)
    }

    pub fn lufs(&self) -> f32 {
        self.meter.lufs
    }
}

impl AudioNode for MasterNode {
    fn name(&self) -> &str {
        "master"
    }

    fn num_inputs(&self) -> usize {
        1
    }

    fn num_outputs(&self) -> usize {
        1
    }

    #[inline]
    fn process(&mut self, inputs: &[&AudioBuffer], output: &mut AudioBuffer) {
        if let Some(input) = inputs.first() {
            *output = (*input).clone();
            if let Some(limiter) = &mut self.limiter {
                limiter.process(output);
            }
            self.meter.process(output);
            for sample in output.samples_mut() {
                *sample = dhvani::dsp::sanitize_sample(*sample);
            }
        }
    }
}

// --- Graph-based audio pipeline ---

/// Node IDs for sources in the audio graph.
struct SourceNodes {
    input: NodeId,
    gain: NodeId,
    dsp: NodeId,
    gain_value: f32,
    pan_value: f32,
}

/// A graph-based audio pipeline that routes multiple sources through
/// per-source DSP, a mixer, and master processing.
///
/// Uses [`dhvani::graph`] for topologically-sorted, real-time safe execution.
/// The graph is rebuilt and compiled whenever sources are added or removed,
/// with the new [`ExecutionPlan`] swapped into the processor lock-free.
pub struct AudioPipeline {
    config: AudioMixerConfig,
    source_nodes: HashMap<AudioSourceId, SourceNodes>,
    mixer_node_id: NodeId,
    master_node_id: NodeId,
    processor: GraphProcessor,
    dirty: bool,
    /// Per-source metering (peak L/R).
    source_meters: HashMap<AudioSourceId, dhvani::meter::PeakMeter>,
}

impl AudioPipeline {
    /// Create a new graph-based audio pipeline.
    #[must_use]
    pub fn new(config: AudioMixerConfig) -> Self {
        let mixer_node_id = NodeId::next();
        let master_node_id = NodeId::next();

        let processor = GraphProcessor::new(config.channels, config.sample_rate, 1024);

        let mut pipeline = Self {
            config,
            source_nodes: HashMap::new(),
            mixer_node_id,
            master_node_id,
            processor,
            dirty: true,
            source_meters: HashMap::new(),
        };
        pipeline.compile_and_swap();
        pipeline
    }

    /// Add a source to the pipeline. Creates input → gain → DSP → mixer chain.
    pub fn add_source(&mut self, id: AudioSourceId, gain: f32, pan: f32) {
        let input_id = NodeId::next();
        let gain_id = NodeId::next();
        let dsp_id = NodeId::next();

        self.source_nodes.insert(
            id,
            SourceNodes {
                input: input_id,
                gain: gain_id,
                dsp: dsp_id,
                gain_value: gain,
                pan_value: pan,
            },
        );
        self.source_meters
            .insert(id, dhvani::meter::PeakMeter::new());

        self.dirty = true;
        self.compile_and_swap();
        tracing::debug!(source_id = %id, gain, pan, "audio pipeline: source added");
    }

    /// Update gain and pan for an existing source.
    pub fn update_source(&mut self, id: AudioSourceId, gain: f32, pan: f32) -> bool {
        if let Some(nodes) = self.source_nodes.get_mut(&id) {
            nodes.gain_value = gain;
            nodes.pan_value = pan;
            self.dirty = true;
            self.compile_and_swap();
            true
        } else {
            false
        }
    }

    /// Remove a source from the pipeline.
    pub fn remove_source(&mut self, id: AudioSourceId) -> bool {
        if self.source_nodes.remove(&id).is_some() {
            self.source_meters.remove(&id);
            self.dirty = true;
            self.compile_and_swap();
            tracing::debug!(source_id = %id, "audio pipeline: source removed");
            true
        } else {
            false
        }
    }

    /// Build a fresh graph from current source_nodes, compile it, and swap
    /// the execution plan into the processor.
    fn compile_and_swap(&mut self) {
        let mut graph = Graph::new();
        graph.add_node(self.mixer_node_id, Box::new(MixerNode));
        graph.add_node(self.master_node_id, Box::new(MasterNode::new(&self.config)));
        graph.connect(self.mixer_node_id, self.master_node_id);

        for nodes in self.source_nodes.values() {
            graph.add_node(
                nodes.input,
                Box::new(InputNode::new(
                    self.config.channels,
                    self.config.sample_rate,
                )),
            );
            graph.add_node(nodes.gain, Box::new(GainNode::new(nodes.gain_value)));
            graph.add_node(nodes.dsp, Box::new(DspChainNode::new(nodes.pan_value)));

            graph.connect(nodes.input, nodes.gain);
            graph.connect(nodes.gain, nodes.dsp);
            graph.connect(nodes.dsp, self.mixer_node_id);
        }

        // compile() consumes the Graph — that's fine, we rebuild each time.
        match graph.compile() {
            Ok(plan) => {
                let handle = self.processor.swap_handle();
                handle.swap(plan);
                self.dirty = false;
            }
            Err(e) => {
                tracing::error!("audio graph compilation failed: {e}");
            }
        }
    }

    /// Process one cycle: run the graph processor and return the output.
    ///
    /// Source input buffers should be fed into the graph's input nodes
    /// before calling this. Returns the master output buffer.
    #[must_use]
    pub fn process(&mut self) -> Option<AudioBuffer> {
        self.processor.process().cloned()
    }

    /// Get per-source peak levels (L, R) in linear amplitude.
    #[must_use]
    pub fn source_peak(&self, id: AudioSourceId) -> Option<[f32; 2]> {
        self.source_meters.get(&id).map(|m| m.load())
    }

    /// Number of sources in the pipeline.
    #[must_use]
    pub fn source_count(&self) -> usize {
        self.source_nodes.len()
    }

    /// Current configuration.
    #[must_use]
    pub fn config(&self) -> &AudioMixerConfig {
        &self.config
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::audio::AudioMixerConfig;

    #[test]
    fn pipeline_new() {
        let pipeline = AudioPipeline::new(AudioMixerConfig::default());
        assert_eq!(pipeline.source_count(), 0);
    }

    #[test]
    fn pipeline_add_remove_source() {
        let mut pipeline = AudioPipeline::new(AudioMixerConfig::default());
        let id = uuid::Uuid::new_v4();
        pipeline.add_source(id, 1.0, 0.0);
        assert_eq!(pipeline.source_count(), 1);
        assert!(pipeline.remove_source(id));
        assert_eq!(pipeline.source_count(), 0);
    }

    #[test]
    fn pipeline_multiple_sources() {
        let mut pipeline = AudioPipeline::new(AudioMixerConfig::default());
        let id1 = uuid::Uuid::new_v4();
        let id2 = uuid::Uuid::new_v4();
        let id3 = uuid::Uuid::new_v4();
        pipeline.add_source(id1, 1.0, -1.0);
        pipeline.add_source(id2, 0.5, 0.0);
        pipeline.add_source(id3, 1.0, 1.0);
        assert_eq!(pipeline.source_count(), 3);
    }

    #[test]
    fn pipeline_source_peak_default() {
        let mut pipeline = AudioPipeline::new(AudioMixerConfig::default());
        let id = uuid::Uuid::new_v4();
        pipeline.add_source(id, 1.0, 0.0);
        let peak = pipeline.source_peak(id).unwrap();
        assert_eq!(peak, [0.0, 0.0]);
    }
}

//! Audio mixer: collects buffers from multiple sources, applies per-source
//! DSP (gain, pan, EQ, compressor), mixes, and applies master processing.
//!
//! All DSP and mixing is delegated to [`dhvani`].

use std::collections::HashMap;

use dhvani::buffer::{AudioBuffer, BufferPool};
use dhvani::dsp;
use dhvani::meter::LevelMeter;
use tracing;
use uuid::Uuid;

use super::{AudioMixerConfig, AudioSourceConfig, AudioSourceEntry, AudioSourceId};

/// Per-source DSP state (stateful effects that need to persist across buffers).
struct SourceDsp {
    pan: dsp::StereoPanner,
    gain_smoother: dsp::GainSmoother,
    compressor: Option<dsp::Compressor>,
    eq: Option<dsp::ParametricEq>,
    graphic_eq: Option<dsp::GraphicEq>,
    deesser: Option<dsp::DeEsser>,
    reverb: Option<dsp::Reverb>,
    delay: Option<dsp::DelayLine>,
    noise_gate_threshold: Option<f32>,
    meter: LevelMeter,
}

/// The audio mixer: manages sources, applies DSP, and mixes to a master bus.
///
/// Uses a [`BufferPool`] to reduce per-frame allocations in the real-time path,
/// and [`GainSmoother`](dsp::GainSmoother) for click-free volume transitions.
pub struct AudioMixer {
    config: AudioMixerConfig,
    sources: Vec<AudioSourceEntry>,
    source_dsp: HashMap<AudioSourceId, SourceDsp>,
    master_limiter: Option<dsp::EnvelopeLimiter>,
    master_meter: LevelMeter,
    #[allow(dead_code)] // Used for RT allocation pooling in future mix() optimization
    buffer_pool: BufferPool,
}

impl AudioMixer {
    /// Create a new mixer with the given configuration.
    #[must_use]
    pub fn new(config: AudioMixerConfig) -> Self {
        let master_limiter = if config.master_limiter {
            dsp::EnvelopeLimiter::new(dsp::LimiterParams::default(), config.sample_rate).ok()
        } else {
            None
        };

        let buffer_pool = BufferPool::new(
            8, // pre-allocate 8 buffers
            config.channels,
            1024, // default buffer frames
            config.sample_rate,
        );

        Self {
            master_meter: LevelMeter::new(config.channels as usize, config.sample_rate as f32),
            config,
            sources: Vec::new(),
            source_dsp: HashMap::new(),
            master_limiter,
            buffer_pool,
        }
    }

    /// Add a new audio source. Returns its unique ID.
    pub fn add_source(&mut self, config: AudioSourceConfig) -> AudioSourceId {
        let id = Uuid::new_v4();
        let mut gain_smoother = dsp::GainSmoother::from_params(dsp::GainSmootherParams::default());
        // Pre-set to initial gain so first buffer isn't smoothed from unity
        gain_smoother.reset(dsp::db_to_amplitude(config.gain_db));

        let dsp_state = SourceDsp {
            pan: dsp::StereoPanner::new(config.pan),
            gain_smoother,
            compressor: None,
            eq: None,
            graphic_eq: None,
            deesser: None,
            reverb: None,
            delay: None,
            noise_gate_threshold: None,
            meter: LevelMeter::new(
                self.config.channels as usize,
                self.config.sample_rate as f32,
            ),
        };
        tracing::debug!(source_id = %id, name = %config.name, "mixer: source added");
        self.sources.push(AudioSourceEntry { id, config });
        self.source_dsp.insert(id, dsp_state);
        id
    }

    /// Remove a source by ID. Returns `true` if found.
    pub fn remove_source(&mut self, id: AudioSourceId) -> bool {
        let before = self.sources.len();
        self.sources.retain(|s| s.id != id);
        self.source_dsp.remove(&id);
        let removed = self.sources.len() < before;
        if removed {
            tracing::debug!(source_id = %id, "mixer: source removed");
        }
        removed
    }

    /// Get source configuration by ID.
    #[must_use]
    pub fn get_source(&self, id: AudioSourceId) -> Option<&AudioSourceEntry> {
        self.sources.iter().find(|s| s.id == id)
    }

    /// Update source configuration. Returns `true` if found.
    pub fn update_source(&mut self, id: AudioSourceId, config: AudioSourceConfig) -> bool {
        if let Some(entry) = self.sources.iter_mut().find(|s| s.id == id) {
            if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
                dsp_state.pan.set_pan(config.pan);
            }
            entry.config = config;
            true
        } else {
            false
        }
    }

    /// Enable per-source compression with the given parameters.
    pub fn set_source_compressor(
        &mut self,
        id: AudioSourceId,
        params: dsp::CompressorParams,
    ) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            dsp_state.compressor = dsp::Compressor::new(params, self.config.sample_rate).ok();
            true
        } else {
            false
        }
    }

    /// Enable per-source EQ with the given bands.
    pub fn set_source_eq(&mut self, id: AudioSourceId, bands: Vec<dsp::EqBandConfig>) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            dsp_state.eq = Some(dsp::ParametricEq::new(
                bands,
                self.config.sample_rate,
                self.config.channels,
            ));
            true
        } else {
            false
        }
    }

    /// Enable per-source graphic EQ with the given settings.
    pub fn set_source_graphic_eq(
        &mut self,
        id: AudioSourceId,
        settings: dsp::GraphicEqSettings,
    ) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            let mut geq = dsp::GraphicEq::new(self.config.sample_rate, self.config.channels);
            geq.set_settings(settings);
            dsp_state.graphic_eq = Some(geq);
            true
        } else {
            false
        }
    }

    /// Enable per-source de-esser with the given parameters.
    pub fn set_source_deesser(&mut self, id: AudioSourceId, params: dsp::DeEsserParams) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            dsp_state.deesser =
                dsp::DeEsser::new(params, self.config.sample_rate, self.config.channels).ok();
            true
        } else {
            false
        }
    }

    /// Enable per-source reverb with the given parameters.
    pub fn set_source_reverb(&mut self, id: AudioSourceId, params: dsp::ReverbParams) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            dsp_state.reverb = dsp::Reverb::new(params, self.config.sample_rate).ok();
            true
        } else {
            false
        }
    }

    /// Enable per-source delay with the given parameters.
    ///
    /// `delay_ms` is the delay time (clamped to `0.1..=5000.0`), `feedback`
    /// controls echo repetition (clamped to `0.0..=0.95` to prevent infinite
    /// buildup), `mix` controls dry/wet balance (clamped to `0.0..=1.0`).
    pub fn set_source_delay(
        &mut self,
        id: AudioSourceId,
        delay_ms: f32,
        feedback: f32,
        mix: f32,
    ) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            let delay_ms = delay_ms.clamp(0.1, 5000.0);
            let feedback = feedback.clamp(0.0, 0.95);
            let mix = mix.clamp(0.0, 1.0);
            dsp_state.delay = Some(dsp::DelayLine::new(
                delay_ms,
                delay_ms * 2.0,
                feedback,
                mix,
                self.config.sample_rate,
                self.config.channels,
            ));
            true
        } else {
            false
        }
    }

    /// Enable per-source noise gate. Samples below the threshold (in linear
    /// amplitude, e.g. 0.01) are silenced. Threshold is clamped to `0.0..=1.0`.
    pub fn set_source_noise_gate(&mut self, id: AudioSourceId, threshold: f32) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            dsp_state.noise_gate_threshold = Some(threshold.clamp(0.0, 1.0));
            true
        } else {
            false
        }
    }

    /// Disable a specific per-source effect. Pass the effect name:
    /// `"compressor"`, `"eq"`, `"graphic_eq"`, `"deesser"`, `"reverb"`,
    /// `"delay"`, `"noise_gate"`.
    pub fn clear_source_effect(&mut self, id: AudioSourceId, effect: &str) -> bool {
        if let Some(dsp_state) = self.source_dsp.get_mut(&id) {
            match effect {
                "compressor" => dsp_state.compressor = None,
                "eq" => dsp_state.eq = None,
                "graphic_eq" => dsp_state.graphic_eq = None,
                "deesser" => dsp_state.deesser = None,
                "reverb" => dsp_state.reverb = None,
                "delay" => dsp_state.delay = None,
                "noise_gate" => dsp_state.noise_gate_threshold = None,
                _ => return false,
            }
            true
        } else {
            false
        }
    }

    /// All registered sources.
    #[must_use]
    pub fn sources(&self) -> &[AudioSourceEntry] {
        &self.sources
    }

    /// Number of sources.
    #[must_use]
    pub fn source_count(&self) -> usize {
        self.sources.len()
    }

    /// Current mixer configuration.
    #[must_use]
    pub fn config(&self) -> &AudioMixerConfig {
        &self.config
    }

    /// Per-source peak level for a channel in dB (post-DSP, pre-mix).
    #[must_use]
    pub fn source_peak_db(&self, id: AudioSourceId, channel: usize) -> Option<f32> {
        self.source_dsp
            .get(&id)
            .map(|dsp| dsp.meter.peak_db(channel))
    }

    /// Per-source RMS level for a channel in dB (post-DSP, pre-mix).
    #[must_use]
    pub fn source_rms_db(&self, id: AudioSourceId, channel: usize) -> Option<f32> {
        self.source_dsp
            .get(&id)
            .map(|dsp| dsp.meter.rms_db(channel))
    }

    /// Master peak level for a channel in dB.
    #[must_use]
    pub fn master_peak_db(&self, channel: usize) -> f32 {
        self.master_meter.peak_db(channel)
    }

    /// Master RMS level for a channel in dB.
    #[must_use]
    pub fn master_rms_db(&self, channel: usize) -> f32 {
        self.master_meter.rms_db(channel)
    }

    /// Integrated LUFS of the master bus.
    #[must_use]
    pub fn master_lufs(&self) -> f32 {
        self.master_meter.lufs
    }

    /// Mix the given per-source audio buffers into a single master buffer.
    ///
    /// `source_buffers` maps source IDs to their captured audio buffers.
    /// Sources not in the map (or muted) are treated as silence.
    /// Returns `None` if no sources contributed audio.
    #[inline]
    pub fn mix(
        &mut self,
        source_buffers: &mut HashMap<AudioSourceId, AudioBuffer>,
    ) -> Option<AudioBuffer> {
        let mut to_mix: Vec<AudioBuffer> = Vec::new();

        for entry in &self.sources {
            if entry.config.muted {
                continue;
            }

            let Some(buf) = source_buffers.remove(&entry.id) else {
                continue;
            };

            let mut buf = buf;

            // Apply per-source DSP chain:
            //   gain → EQ → noise gate → compressor → de-esser
            //   → delay → reverb → pan → sanitize → meter
            //
            // EQ before gate so HP filter removes rumble that would hold gate open.
            if let Some(dsp_state) = self.source_dsp.get_mut(&entry.id) {
                // Smoothed gain (click-free volume transitions)
                let target_gain = dsp::db_to_amplitude(entry.config.gain_db);
                let smoothed_gain = dsp_state.gain_smoother.smooth(target_gain);
                if (smoothed_gain - 1.0).abs() > f32::EPSILON {
                    buf.apply_gain(smoothed_gain);
                }

                // EQ (parametric or graphic — parametric takes priority if both set)
                if let Some(eq) = &mut dsp_state.eq {
                    eq.process(&mut buf);
                } else if let Some(geq) = &mut dsp_state.graphic_eq {
                    geq.process(&mut buf);
                }

                // Noise gate after EQ (HP filter removes rumble first)
                if let Some(threshold) = dsp_state.noise_gate_threshold {
                    dsp::noise_gate(&mut buf, threshold);
                }

                // Dynamics
                if let Some(comp) = &mut dsp_state.compressor {
                    comp.process(&mut buf);
                }
                if let Some(deesser) = &mut dsp_state.deesser {
                    deesser.process(&mut buf);
                }

                // Time-based effects
                if let Some(delay) = &mut dsp_state.delay {
                    delay.process(&mut buf);
                }
                if let Some(reverb) = &mut dsp_state.reverb {
                    reverb.process(&mut buf);
                }

                // Spatial
                dsp_state.pan.process(&mut buf);

                // Sanitize after DSP chain to catch NaN/Inf from filter instability
                for sample in buf.samples_mut() {
                    *sample = dsp::sanitize_sample(*sample);
                }

                dsp_state.meter.process(&buf);
            }

            to_mix.push(buf);
        }

        if to_mix.is_empty() {
            return None;
        }

        // Mix all sources
        let refs: Vec<&AudioBuffer> = to_mix.iter().collect();
        let mut mixed = dhvani::buffer::mix(&refs).ok()?;

        // Master gain
        let master_gain = dsp::db_to_amplitude(self.config.master_gain_db);
        if (master_gain - 1.0).abs() > f32::EPSILON {
            mixed.apply_gain(master_gain);
        }

        // Master limiter
        if let Some(limiter) = &mut self.master_limiter {
            limiter.process(&mut mixed);
        }

        // Update metering
        self.master_meter.process(&mixed);

        Some(mixed)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn test_buffer(value: f32, frames: usize) -> AudioBuffer {
        AudioBuffer::from_interleaved(vec![value; frames * 2], 2, 48000).unwrap()
    }

    #[test]
    fn mixer_new() {
        let mixer = AudioMixer::new(AudioMixerConfig::default());
        assert_eq!(mixer.source_count(), 0);
        assert_eq!(mixer.config().sample_rate, 48000);
    }

    #[test]
    fn add_and_remove_source() {
        let mut mixer = AudioMixer::new(AudioMixerConfig::default());
        let id = mixer.add_source(AudioSourceConfig::new("Mic"));
        assert_eq!(mixer.source_count(), 1);
        assert!(mixer.get_source(id).is_some());
        assert_eq!(mixer.get_source(id).unwrap().config.name, "Mic");

        assert!(mixer.remove_source(id));
        assert_eq!(mixer.source_count(), 0);
    }

    #[test]
    fn mix_single_source() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Test"));

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));

        let result = mixer.mix(&mut buffers);
        assert!(result.is_some());
        let mixed = result.unwrap();
        assert_eq!(mixed.channels(), 2);
        assert_eq!(mixed.frames(), 1024);
    }

    #[test]
    fn mix_two_sources() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id1 = mixer.add_source(AudioSourceConfig::new("Source 1"));
        let id2 = mixer.add_source(AudioSourceConfig::new("Source 2"));

        let mut buffers = HashMap::new();
        buffers.insert(id1, test_buffer(0.3, 512));
        buffers.insert(id2, test_buffer(0.2, 512));

        let result = mixer.mix(&mut buffers);
        assert!(result.is_some());
        let mixed = result.unwrap();
        // Mixed is sum of both after equal-power panning (~0.707x each):
        // (0.3 + 0.2) * 0.707 ≈ 0.354
        let peak = mixed.peak();
        assert!(peak > 0.3 && peak < 0.4, "peak={peak}");
    }

    #[test]
    fn muted_source_excluded() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let mut cfg = AudioSourceConfig::new("Muted");
        cfg.muted = true;
        let id = mixer.add_source(cfg);

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 512));

        let result = mixer.mix(&mut buffers);
        assert!(result.is_none());
    }

    #[test]
    fn source_gain_applied() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let mut cfg = AudioSourceConfig::new("Quiet");
        cfg.gain_db = -6.0; // ~0.501x
        let id = mixer.add_source(cfg);

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(1.0, 512));

        let result = mixer.mix(&mut buffers).unwrap();
        let peak = result.peak();
        // -6dB ≈ 0.501, then equal-power pan at center ≈ 0.707x → ~0.354
        assert!(peak > 0.3 && peak < 0.4, "peak={peak}");
    }

    #[test]
    fn master_limiter_clamps() {
        let mut mixer = AudioMixer::new(AudioMixerConfig::default());
        let id = mixer.add_source(AudioSourceConfig::new("Loud"));

        let mut buffers = HashMap::new();
        // Very loud signal
        buffers.insert(id, test_buffer(2.0, 1024));

        let result = mixer.mix(&mut buffers).unwrap();
        let peak = result.peak();
        // Limiter should reduce peak below ~1.0
        assert!(peak < 1.5, "limiter should reduce peak, got {peak}");
    }

