        assert!(mixer.set_source_graphic_eq(id, settings));

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        let result = mixer.mix(&mut buffers);
        assert!(result.is_some());
    }

    #[test]
    fn reverb_processes_without_error() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Reverbed"));
        assert!(mixer.set_source_reverb(
            id,
            dsp::ReverbParams {
                room_size: 0.8,
                damping: 0.5,
                mix: 0.3,
            },
        ));

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        let result = mixer.mix(&mut buffers);
        assert!(result.is_some());
    }

    #[test]
    fn delay_processes_without_error() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Delayed"));
        assert!(mixer.set_source_delay(id, 50.0, 0.3, 0.5));

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        let result = mixer.mix(&mut buffers);
        assert!(result.is_some());
    }

    #[test]
    fn clear_source_effect_works() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Fx"));
        mixer.set_source_noise_gate(id, 0.1);
        assert!(mixer.clear_source_effect(id, "noise_gate"));
        assert!(!mixer.clear_source_effect(id, "nonexistent"));
        assert!(!mixer.clear_source_effect(Uuid::new_v4(), "noise_gate"));
    }

    #[test]
    fn full_dsp_chain() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: true,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Full Chain"));

        // Enable everything
        mixer.set_source_noise_gate(id, 0.01);
        mixer.set_source_eq(
            id,
            vec![dsp::EqBandConfig {
                band_type: dsp::BandType::HighPass,
                freq_hz: 80.0,
                gain_db: 0.0,
                q: 0.707,
                enabled: true,
            }],
        );
        mixer.set_source_compressor(
            id,
            dsp::CompressorParams {
                threshold_db: -20.0,
                ratio: 4.0,
                attack_ms: 5.0,
                release_ms: 50.0,
                makeup_gain_db: 0.0,
                knee_db: 6.0,
                mix: 1.0,
            },
        );
        mixer.set_source_deesser(
            id,
            dsp::DeEsserParams {
                freq_hz: 6000.0,
                threshold_db: -20.0,
                reduction_db: 6.0,
                q: 1.0,
            },
        );
        mixer.set_source_delay(id, 10.0, 0.2, 0.3);
        mixer.set_source_reverb(
            id,
            dsp::ReverbParams {
                room_size: 0.5,
                damping: 0.5,
                mix: 0.2,
            },
        );

        // Run multiple mix cycles to exercise stateful effects
        for _ in 0..5 {
            let mut buffers = HashMap::new();
            buffers.insert(id, test_buffer(0.5, 1024));
            let result = mixer.mix(&mut buffers);
            assert!(result.is_some());
            let mixed = result.unwrap();
            // No NaN/Inf from the full chain
            for &s in mixed.samples() {
                assert!(!s.is_nan(), "full chain produced NaN");
                assert!(!s.is_infinite(), "full chain produced Inf");
            }
        }
    }

    #[test]
    fn sanitize_prevents_inf() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Inf source"));

        let mut buf = test_buffer(0.5, 512);
        for sample in buf.samples_mut() {
            *sample = f32::INFINITY;
        }

        let mut buffers = HashMap::new();
        buffers.insert(id, buf);
        let result = mixer.mix(&mut buffers).unwrap();
        for &s in result.samples() {
            assert!(!s.is_nan(), "output contains NaN");
            assert!(!s.is_infinite(), "output contains Inf");
        }
    }

    #[test]
    fn eq_mutual_exclusion() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("EQ Test"));

        // Set both parametric and graphic EQ
        mixer.set_source_eq(
            id,
            vec![dsp::EqBandConfig {
                band_type: dsp::BandType::HighPass,
                freq_hz: 80.0,
                gain_db: 0.0,
                q: 0.707,
                enabled: true,
            }],
        );
        mixer.set_source_graphic_eq(
            id,
            dsp::GraphicEqSettings {
                enabled: true,
                bands: [6.0; 10],
            },
        );

        // Both set — should still process without error (parametric wins)
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        assert!(mixer.mix(&mut buffers).is_some());

        // Clear parametric — graphic should take over
        mixer.clear_source_effect(id, "eq");
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        assert!(mixer.mix(&mut buffers).is_some());
    }

    #[test]
    fn effect_toggle_clear_and_readd() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Toggle"));

        // Add reverb, mix, clear, mix, re-add, mix
        mixer.set_source_reverb(
            id,
            dsp::ReverbParams {
                room_size: 0.8,
                damping: 0.5,
                mix: 0.5,
            },
        );
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        assert!(mixer.mix(&mut buffers).is_some());

        mixer.clear_source_effect(id, "reverb");
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        assert!(mixer.mix(&mut buffers).is_some());

        // Re-add with different params — should be fresh state
        mixer.set_source_reverb(
            id,
            dsp::ReverbParams {
                room_size: 0.3,
                damping: 0.8,
                mix: 0.2,
            },
        );
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        let result = mixer.mix(&mut buffers).unwrap();
        for &s in result.samples() {
            assert!(!s.is_nan(), "re-added reverb produced NaN");
        }
    }

    #[test]
    fn compressor_reduces_loud_signal() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Comp Check"));
        mixer.set_source_compressor(
            id,
            dsp::CompressorParams {
                threshold_db: -20.0,
                ratio: 8.0,
                attack_ms: 0.1,
                release_ms: 10.0,
                makeup_gain_db: 0.0,
                knee_db: 0.0,
                mix: 1.0,
            },
        );

        // Run several cycles so compressor converges
        let mut last_peak = 0.0_f32;
        for _ in 0..10 {
            let mut buffers = HashMap::new();
            buffers.insert(id, test_buffer(0.9, 1024));
            let result = mixer.mix(&mut buffers).unwrap();
            last_peak = result.peak();
        }
        // 0.9 input → after pan (~0.636) → above -20dB threshold → compressed
        // Should be measurably less than uncompressed peak
        assert!(
            last_peak < 0.7,
            "compressor should reduce peak, got {last_peak}"
        );
    }

    #[test]
    fn delay_feedback_clamped() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Delay Clamp"));
        // feedback > 1.0 should be clamped to 0.95
        mixer.set_source_delay(id, 10.0, 5.0, 0.5);

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        let result = mixer.mix(&mut buffers).unwrap();
        // Should not blow up despite extreme feedback input
        assert!(
            result.peak() < 2.0,
            "clamped feedback should prevent blowup"
        );
    }

    #[test]
    fn master_gain_applied() {
        let mut mixer = AudioMixer::new(AudioMixerConfig {
            master_limiter: false,
            master_gain_db: -6.0,
            ..Default::default()
        });
        let id = mixer.add_source(AudioSourceConfig::new("Src"));

        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.8, 1024));
        let result = mixer.mix(&mut buffers).unwrap();
        let peak = result.peak();
        // -6dB master gain should attenuate to ~half, plus pan factor
        assert!(peak < 0.5, "master gain should attenuate, peak={peak}");
    }

    #[test]
    fn clear_all_effect_types() {
        let mut mixer = AudioMixer::new(AudioMixerConfig::default());
        let id = mixer.add_source(AudioSourceConfig::new("AllFx"));

        // Set all effects
        mixer.set_source_noise_gate(id, 0.01);
        mixer.set_source_eq(
            id,
            vec![dsp::EqBandConfig {
                band_type: dsp::BandType::HighPass,
                freq_hz: 80.0,
                gain_db: 0.0,
                q: 0.707,
                enabled: true,
            }],
        );
        mixer.set_source_graphic_eq(
            id,
            dsp::GraphicEqSettings {
                enabled: true,
                bands: [0.0; 10],
            },
        );
        mixer.set_source_compressor(
            id,
            dsp::CompressorParams {
                threshold_db: -20.0,
                ratio: 4.0,
                attack_ms: 5.0,
                release_ms: 50.0,
                makeup_gain_db: 0.0,
                knee_db: 0.0,
                mix: 1.0,
            },
        );
        mixer.set_source_deesser(
            id,
            dsp::DeEsserParams {
                freq_hz: 6000.0,
                threshold_db: -20.0,
                reduction_db: 6.0,
                q: 1.0,
            },
        );
        mixer.set_source_delay(id, 10.0, 0.2, 0.3);
        mixer.set_source_reverb(
            id,
            dsp::ReverbParams {
                room_size: 0.5,
                damping: 0.5,
                mix: 0.2,
            },
        );

        // Clear all individually
        for effect in &[
            "noise_gate",
            "eq",
            "graphic_eq",
            "compressor",
            "deesser",
            "delay",
            "reverb",
        ] {
            assert!(
                mixer.clear_source_effect(id, effect),
                "clearing {effect} should succeed"
            );
        }

        // Mix should still work with all effects cleared
        let mut buffers = HashMap::new();
        buffers.insert(id, test_buffer(0.5, 1024));
        assert!(mixer.mix(&mut buffers).is_some());
    }
}

//! Audio capture, mixing, and DSP pipeline.
//!
//! Delegates to [`dhvani`] for all audio processing:
//! - Capture via PipeWire ([`dhvani::capture`])
//! - Mixing via [`dhvani::buffer::mix`]
//! - DSP effects via [`dhvani::dsp`]
//! - Metering via [`dhvani::meter`]
//! - A/V sync via [`dhvani::clock`]
//! - Graph-based routing via [`dhvani::graph`]
//!
//! # Architecture
//!
//! The audio pipeline supports two modes:
//!
//! **Manual mixer** ([`AudioMixer`]): Simple per-source DSP → mix → master chain.
//! Good for basic use cases with a fixed number of sources.
//!
//! **Graph pipeline** ([`AudioPipeline`]): Node-based routing via [`dhvani::graph`].
//! Supports dynamic source add/remove with real-time safe graph swaps.
//!
//! ```text
//! PipeWire ──► AudioCaptureManager ──► per-source DSP ──► Mixer ──► master DSP ──► output
//!              (multi-device)           (gain, EQ,         (graph     (compressor,
//!                                        compressor)       node)      limiter)
//! ```

pub mod capture;
pub mod graph;
pub mod mixer;

use serde::{Deserialize, Serialize};
use uuid::Uuid;

#[cfg(feature = "pipewire")]
pub use capture::AudioCaptureManager;
pub use graph::AudioPipeline;
pub use mixer::AudioMixer;

/// Unique identifier for an audio source.
pub type AudioSourceId = Uuid;

/// Configuration for an audio source.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AudioSourceConfig {
    /// Human-readable name (e.g. "Desktop Audio", "Microphone").
    pub name: String,
    /// PipeWire device ID. `None` = default device.
    pub device_id: Option<u32>,
    /// Gain in dB applied before mixing (0.0 = unity).
    pub gain_db: f32,
    /// Whether this source is muted.
    pub muted: bool,
    /// Stereo pan: -1.0 (left) to 1.0 (right), 0.0 = center.
    pub pan: f32,
}

impl Default for AudioSourceConfig {
    fn default() -> Self {
        Self {
            name: "Audio".into(),
            device_id: None,
            gain_db: 0.0,
            muted: false,
            pan: 0.0,
        }
    }
}

impl AudioSourceConfig {
    /// Create a config with the given name.
    #[must_use]
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            ..Default::default()
        }
    }
}

/// Configuration for the audio mixer.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AudioMixerConfig {
    /// Output sample rate in Hz.
    pub sample_rate: u32,
    /// Output channels (1 = mono, 2 = stereo).
    pub channels: u32,
    /// Master gain in dB.
    pub master_gain_db: f32,
    /// Whether to apply a limiter on the master bus.
    pub master_limiter: bool,
}

impl Default for AudioMixerConfig {
    fn default() -> Self {
        Self {
            sample_rate: 48000,
            channels: 2,
            master_gain_db: 0.0,
            master_limiter: true,
        }
    }
}

/// A managed audio source with its ID and configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AudioSourceEntry {
    /// Unique source ID.
    pub id: AudioSourceId,
    /// Source configuration.
    pub config: AudioSourceConfig,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn source_config_default() {
        let cfg = AudioSourceConfig::default();
        assert_eq!(cfg.gain_db, 0.0);
        assert!(!cfg.muted);
        assert_eq!(cfg.pan, 0.0);
        assert!(cfg.device_id.is_none());
    }

    #[test]
    fn source_config_new() {
        let cfg = AudioSourceConfig::new("Desktop Audio");
        assert_eq!(cfg.name, "Desktop Audio");
    }

    #[test]
    fn mixer_config_default() {
        let cfg = AudioMixerConfig::default();
        assert_eq!(cfg.sample_rate, 48000);
        assert_eq!(cfg.channels, 2);
        assert!(cfg.master_limiter);
    }

    #[test]
    fn source_config_serde() {
        let cfg = AudioSourceConfig {
            name: "Mic".into(),
            device_id: Some(42),
            gain_db: -3.0,
            muted: false,
            pan: 0.5,
        };
        let json = serde_json::to_string(&cfg).unwrap();
        let back: AudioSourceConfig = serde_json::from_str(&json).unwrap();
        assert_eq!(back.name, "Mic");
        assert_eq!(back.device_id, Some(42));
        assert!((back.gain_db - (-3.0)).abs() < f32::EPSILON);
    }

    #[test]
    fn mixer_config_serde() {
        let cfg = AudioMixerConfig {
            sample_rate: 44100,
            channels: 1,
            master_gain_db: -6.0,
            master_limiter: false,
        };
        let json = serde_json::to_string(&cfg).unwrap();
        let back: AudioMixerConfig = serde_json::from_str(&json).unwrap();
        assert_eq!(back.sample_rate, 44100);
        assert!(!back.master_limiter);
    }
}

//! Encoding pipeline: hardware selection via ai-hwaccel, encoding via tarang.
//!
//! When the `hwaccel` feature is enabled, [`EncodePipeline::init`] probes for
//! GPU hardware via [`ai_hwaccel::AcceleratorRegistry`] and selects the best
//! available encoder:
//!
//! 1. **VA-API** (feature `vaapi`) — hardware H.264 on Intel/AMD GPUs
//! 2. **OpenH264** (feature `openh264-enc`) — software H.264 fallback
//!
//! Uses ranga for ARGB8888 → YUV420p / NV12 color space conversion.

use serde::{Deserialize, Serialize};

use crate::output::EncodedPacket;
use crate::source::RawFrame;

/// Encoder configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EncoderConfig {
    /// Target codec.
    pub codec: VideoCodec,
    /// Target bitrate in kbps.
    pub bitrate_kbps: u32,
    /// Keyframe interval in frames.
    pub keyframe_interval: u32,
    /// Prefer hardware encoding when available.
    pub prefer_hardware: bool,
}

impl Default for EncoderConfig {
    fn default() -> Self {
        Self {
            codec: VideoCodec::H264,
            bitrate_kbps: 6000,
            keyframe_interval: 60,
            prefer_hardware: true,
        }
    }
}

/// Supported video codecs for output.
#[non_exhaustive]
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum VideoCodec {
    H264,
    H265,
    VP9,
    AV1,
}

/// Which encoder backend is active.
#[non_exhaustive]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EncoderBackend {
    /// VA-API hardware encoder (Intel/AMD GPU).
    Vaapi,
    /// OpenH264 software encoder.
    OpenH264,
    /// No encoder available.
    None,
}

impl std::fmt::Display for EncoderBackend {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Vaapi => write!(f, "VA-API (hardware)"),
            Self::OpenH264 => write!(f, "OpenH264 (software)"),
            Self::None => write!(f, "none"),
        }
    }
}

/// The encode pipeline consumes composited frames and produces encoded packets.
///
/// Selects the best available encoder backend based on hardware detection
/// and enabled features. Use [`backend`] to check which encoder is active.
pub struct EncodePipeline {
    pub config: EncoderConfig,
    encoder: EncoderInner,
    frames_encoded: u64,
}

enum EncoderInner {
    Uninitialised,
    #[cfg(feature = "vaapi")]
    Vaapi(tarang::video::VaapiEncoder),
    #[cfg(feature = "openh264-enc")]
    OpenH264(Box<tarang::video::OpenH264Encoder>),
}

impl EncodePipeline {
    /// Create a new encode pipeline. Call [`init`] before encoding.
    #[must_use]
    pub fn new(config: EncoderConfig) -> Self {
        Self {
            config,
            encoder: EncoderInner::Uninitialised,
            frames_encoded: 0,
        }
    }

    /// Initialise the encoder for the given resolution and framerate.
    ///
    /// When `prefer_hardware` is true and the `hwaccel` feature is enabled,
    /// probes for GPU hardware and selects VA-API if available. Falls back
    /// to OpenH264 software encoding otherwise.
    pub fn init(&mut self, width: u32, height: u32, fps: u32) -> anyhow::Result<()> {
        let bitrate_bps = self.config.bitrate_kbps * 1000;

        // Try hardware encoder first
        if self.config.prefer_hardware
            && let Some(encoder) = self.try_hw_encoder(width, height, fps, bitrate_bps)
        {
            self.encoder = encoder;
            return Ok(());
        }

        // Fall back to software encoder
        self.encoder = self.try_sw_encoder(width, height, fps, bitrate_bps)?;
        Ok(())
    }

    /// Attempt hardware encoder selection via ai-hwaccel.
    fn try_hw_encoder(
        &self,
        width: u32,
        height: u32,
        fps: u32,
        bitrate_bps: u32,
    ) -> Option<EncoderInner> {
        let _ = (width, height, fps, bitrate_bps);

        #[cfg(all(feature = "hwaccel", feature = "vaapi"))]
        {
            if self.config.codec != VideoCodec::H264 {
                tracing::debug!("VA-API only supports H.264, skipping hw encoder");
                return None;
            }

            // Use disk-cached registry to avoid re-probing hardware every run.
            // Cache persists to $XDG_CACHE_HOME/ai-hwaccel/registry.json with 60s TTL.
            let registry =
                ai_hwaccel::DiskCachedRegistry::new(std::time::Duration::from_secs(60)).get();
            let has_gpu = registry
                .all_profiles()
                .iter()
                .any(|p| p.accelerator.is_gpu());

            if !has_gpu {
                tracing::debug!("no GPU detected, skipping VA-API");
                return None;
            }

            let vaapi_config = tarang::video::VaapiEncoderConfig {
                codec: tarang::core::VideoCodec::H264,
                width,
                height,
                bitrate_bps,
                frame_rate_num: fps,
                frame_rate_den: 1,
                device: None, // auto-detect
            };

            match tarang::video::VaapiEncoder::new(&vaapi_config) {
                Ok(enc) => {
                    tracing::info!("encoder: VA-API H.264 ({})", enc.driver_name());
                    return Some(EncoderInner::Vaapi(enc));
                }
                Err(e) => {
                    tracing::debug!("VA-API init failed, falling back to software: {e}");
                }
            }
        }

        None
    }

    /// Attempt software encoder initialisation.
    fn try_sw_encoder(
        &self,
        width: u32,
        height: u32,
        fps: u32,
        bitrate_bps: u32,
    ) -> anyhow::Result<EncoderInner> {
        let _ = (width, height, fps, bitrate_bps);

        #[cfg(feature = "openh264-enc")]
        {
            if self.config.codec == VideoCodec::H264 {
                let enc_config = tarang::video::OpenH264EncoderConfig {
                    width,
                    height,
                    bitrate_bps,
                    frame_rate_num: fps,
                    frame_rate_den: 1,
                };
                let enc = tarang::video::OpenH264Encoder::new(&enc_config)?;
                tracing::info!("encoder: OpenH264 (software)");
                return Ok(EncoderInner::OpenH264(Box::new(enc)));
            }
        }

        anyhow::bail!(
            "no encoder available for {:?} — build with --features openh264-enc or --features vaapi",
            self.config.codec
        );
    }

    /// Encode a composited ARGB8888 frame into an encoded packet.
    #[allow(unused_variables)]
    pub fn encode_frame(&mut self, frame: &RawFrame) -> anyhow::Result<EncodedPacket> {
        match &mut self.encoder {
            #[cfg(feature = "vaapi")]
            EncoderInner::Vaapi(enc) => {
                let video_frame = make_video_frame(frame);
                let nal_data = enc.encode(&video_frame)?;
                self.frames_encoded += 1;
                Ok(make_packet(
                    nal_data,
                    frame.pts_us,
                    self.frames_encoded,
                    self.config.keyframe_interval,
                ))
            }
            #[cfg(feature = "openh264-enc")]
            EncoderInner::OpenH264(enc) => {
                let video_frame = make_video_frame(frame);
                let nal_data = enc.encode(&video_frame)?;
                self.frames_encoded += 1;
                Ok(make_packet(
                    nal_data,
                    frame.pts_us,
                    self.frames_encoded,
                    self.config.keyframe_interval,
                ))
            }
            EncoderInner::Uninitialised => {
                anyhow::bail!("encoder not initialised — call init() first");
            }
        }
    }

    /// Which encoder backend is active.
    #[must_use]
    pub fn backend(&self) -> EncoderBackend {
        match &self.encoder {
            #[cfg(feature = "vaapi")]
            EncoderInner::Vaapi(_) => EncoderBackend::Vaapi,
            #[cfg(feature = "openh264-enc")]
            EncoderInner::OpenH264(_) => EncoderBackend::OpenH264,
            EncoderInner::Uninitialised => EncoderBackend::None,
        }
    }

    /// Number of frames encoded so far.
    #[must_use]
    pub fn frames_encoded(&self) -> u64 {
        self.frames_encoded
    }
}

/// Detect and describe the best available encoder without initialising it.
///
/// Useful for `aethersafta info` to show what encoding is available.
#[must_use]
pub fn detect_best_encoder(codec: VideoCodec) -> EncoderBackend {
    #[cfg(all(feature = "hwaccel", feature = "vaapi"))]
    {
        if codec == VideoCodec::H264 {
            let registry =
                ai_hwaccel::DiskCachedRegistry::new(std::time::Duration::from_secs(60)).get();
            let has_gpu = registry
                .all_profiles()
                .iter()
                .any(|p| p.accelerator.is_gpu());
            if has_gpu {
                return EncoderBackend::Vaapi;
            }
        }
    }

    #[cfg(feature = "openh264-enc")]
    if codec == VideoCodec::H264 {
        return EncoderBackend::OpenH264;
    }

    let _ = codec;
    EncoderBackend::None
}

#[cfg(any(feature = "vaapi", feature = "openh264-enc"))]
#[inline]
fn make_video_frame(frame: &RawFrame) -> tarang::core::VideoFrame {
    let yuv = argb_to_yuv420p(&frame.data, frame.width, frame.height);
    tarang::core::VideoFrame {
        data: bytes::Bytes::from(yuv),
        pixel_format: tarang::core::PixelFormat::Yuv420p,
        width: frame.width,
        height: frame.height,
        timestamp: std::time::Duration::from_micros(frame.pts_us),
    }
}

#[cfg(any(feature = "vaapi", feature = "openh264-enc"))]
#[inline]
fn make_packet(
    data: Vec<u8>,
    pts_us: u64,
    frames_encoded: u64,
    keyframe_interval: u32,
) -> EncodedPacket {
    EncodedPacket {
        data,
        pts_us,
        dts_us: pts_us,
        is_keyframe: frames_encoded % keyframe_interval as u64 == 1,
    }
}

/// Convert an ARGB8888 buffer to YUV420p (planar Y, U, V) using BT.709.
///
/// Single-pass direct conversion from ARGB layout — no intermediate copies.
/// BT.709 is correct for HD video (H.264 assumes BT.709 for >= 720p).
#[must_use]
#[inline]
pub fn argb_to_yuv420p(argb: &[u8], width: u32, height: u32) -> Vec<u8> {
    let w = width as usize;
    let h = height as usize;
    let cw = w.div_ceil(2);
    let ch = h.div_ceil(2);
    let mut yuv = vec![0u8; w * h + 2 * cw * ch];

    // Y plane: BT.709 Y = (54*R + 183*G + 19*B) >> 8
    for y in 0..h {
        for x in 0..w {
            let i = (y * w + x) * 4;
            let r = argb[i + 1] as u16;
            let g = argb[i + 2] as u16;
            let b = argb[i + 3] as u16;
            yuv[y * w + x] = ((54 * r + 183 * g + 19 * b) >> 8) as u8;
        }
    }

    // U and V planes (subsampled 2x2)
    let u_off = w * h;
    let v_off = u_off + cw * ch;
    for y in (0..ch * 2).step_by(2) {
        for x in (0..cw * 2).step_by(2) {
            let i = (y * w + x) * 4;
            let r = argb[i + 1] as i32;
            let g = argb[i + 2] as i32;
            let b = argb[i + 3] as i32;
            let ci = (y / 2) * cw + (x / 2);
            yuv[u_off + ci] = ((-29 * r - 99 * g + 128 * b + 128 * 256) >> 8).clamp(0, 255) as u8;
            yuv[v_off + ci] = ((128 * r - 116 * g - 12 * b + 128 * 256) >> 8).clamp(0, 255) as u8;
        }
    }
    yuv
}

/// Convert an NV12 buffer to ARGB8888 using BT.601.
///
/// Single-pass direct conversion — no intermediate copies.
#[must_use]
#[inline]
pub fn nv12_to_argb(nv12: &[u8], width: u32, height: u32) -> Vec<u8> {
    let w = width as usize;
    let h = height as usize;
    let cw = w.div_ceil(2);
    let ch = h.div_ceil(2);
    let uv_off = w * h;
    let uv_stride = cw * 2;
    let mut argb = vec![0u8; w * h * 4];

    for y in 0..h {
        let cy = (y / 2).min(ch.saturating_sub(1));
        for x in 0..w {
            let cx = (x / 2).min(cw.saturating_sub(1));
            let yi = nv12[y * w + x] as i16;
            let uv_idx = uv_off + cy * uv_stride + cx * 2;
            let u = nv12[uv_idx] as i16 - 128;
            let v = nv12[uv_idx + 1] as i16 - 128;
            let oi = (y * w + x) * 4;
            argb[oi] = 255; // A
            argb[oi + 1] = (yi + ((359 * v) >> 8)).clamp(0, 255) as u8; // R
            argb[oi + 2] = (yi - ((88 * u + 183 * v) >> 8)).clamp(0, 255) as u8; // G
            argb[oi + 3] = (yi + ((454 * u) >> 8)).clamp(0, 255) as u8; // B
        }
    }
    argb
}

/// Convert an ARGB8888 buffer to NV12 using BT.601.
///
/// Single-pass direct conversion — no intermediate copies.
#[must_use]
#[inline]
pub fn argb_to_nv12(argb: &[u8], width: u32, height: u32) -> Vec<u8> {
    let w = width as usize;
    let h = height as usize;
    let cw = w.div_ceil(2);
    let ch = h.div_ceil(2);
    let mut nv12 = vec![0u8; w * h + cw * ch * 2];

    // Y plane: BT.601 Y = (77*R + 150*G + 29*B) >> 8
    for y in 0..h {
        for x in 0..w {
            let i = (y * w + x) * 4;
            let r = argb[i + 1] as u16;
            let g = argb[i + 2] as u16;
            let b = argb[i + 3] as u16;
            nv12[y * w + x] = ((77 * r + 150 * g + 29 * b) >> 8) as u8;
        }
    }

    // UV plane (interleaved, subsampled 2x2)
    let uv_off = w * h;
    for y in (0..ch * 2).step_by(2) {
        for x in (0..cw * 2).step_by(2) {
            let i = (y * w + x) * 4;
            let r = argb[i + 1] as i32;
            let g = argb[i + 2] as i32;
            let b = argb[i + 3] as i32;
            let ci = (y / 2) * cw * 2 + x;
            nv12[uv_off + ci] = ((-43 * r - 85 * g + 128 * b + 128 * 256) >> 8).clamp(0, 255) as u8;
            nv12[uv_off + ci + 1] =
                ((128 * r - 107 * g - 21 * b + 128 * 256) >> 8).clamp(0, 255) as u8;
        }
    }
    nv12
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn default_config() {
        let cfg = EncoderConfig::default();
        assert_eq!(cfg.codec, VideoCodec::H264);
        assert_eq!(cfg.bitrate_kbps, 6000);
        assert!(cfg.prefer_hardware);
    }

    #[test]
    fn serde_roundtrip() {
        let cfg = EncoderConfig {
            codec: VideoCodec::AV1,
            bitrate_kbps: 8000,
            keyframe_interval: 120,
            prefer_hardware: false,
        };
        let json = serde_json::to_string(&cfg).unwrap();
        let back: EncoderConfig = serde_json::from_str(&json).unwrap();
        assert_eq!(back.codec, VideoCodec::AV1);
        assert_eq!(back.bitrate_kbps, 8000);
    }

    #[test]
    fn argb_to_yuv_dimensions() {
        let mut argb = vec![0u8; 4 * 4 * 4];
        for chunk in argb.chunks_exact_mut(4) {
            chunk[0] = 255; // A
        }
        let yuv = argb_to_yuv420p(&argb, 4, 4);
        assert_eq!(yuv.len(), 24);
    }

    #[test]
    fn argb_white_to_yuv() {
        let argb = vec![255u8; 2 * 2 * 4];
        let yuv = argb_to_yuv420p(&argb, 2, 2);
        for &y in &yuv[..4] {
            assert!(y > 250, "Y should be near 255, got {y}");
        }
        assert!((yuv[4] as i16 - 128).unsigned_abs() < 5);
        assert!((yuv[5] as i16 - 128).unsigned_abs() < 5);
    }

    #[test]
    fn pipeline_creation() {
        let pipe = EncodePipeline::new(EncoderConfig::default());
        assert_eq!(pipe.frames_encoded(), 0);
        assert_eq!(pipe.backend(), EncoderBackend::None);
    }

    #[test]
    fn detect_best_encoder_returns_something() {
        let best = detect_best_encoder(VideoCodec::H264);
        // Should return OpenH264 or Vaapi depending on features, or None
        println!("best encoder: {best}");
    }

    #[test]
    fn encoder_backend_display() {
        assert_eq!(EncoderBackend::Vaapi.to_string(), "VA-API (hardware)");
        assert_eq!(EncoderBackend::OpenH264.to_string(), "OpenH264 (software)");
        assert_eq!(EncoderBackend::None.to_string(), "none");
    }

    #[test]
    fn argb_to_nv12_dimensions() {
        let mut argb = vec![0u8; 4 * 4 * 4];
        for chunk in argb.chunks_exact_mut(4) {
            chunk[0] = 255;
        }
        let nv12 = argb_to_nv12(&argb, 4, 4);
        assert_eq!(nv12.len(), 24);
    }

    #[test]
    fn nv12_to_argb_dimensions() {
        let nv12 = vec![128u8; 4 * 4 + 4 * 2];
        let argb = nv12_to_argb(&nv12, 4, 4);
        assert_eq!(argb.len(), 4 * 4 * 4);
        for chunk in argb.chunks_exact(4) {
            assert_eq!(chunk[0], 255);
        }
    }

    #[test]
    fn nv12_roundtrip_white() {
        let argb = vec![255u8; 2 * 2 * 4];
        let nv12 = argb_to_nv12(&argb, 2, 2);
        let back = nv12_to_argb(&nv12, 2, 2);
        for chunk in back.chunks_exact(4) {
            assert_eq!(chunk[0], 255, "alpha must be 255");
            assert!(chunk[1] > 250, "R should be near 255, got {}", chunk[1]);
            assert!(chunk[2] > 250, "G should be near 255, got {}", chunk[2]);
            assert!(chunk[3] > 250, "B should be near 255, got {}", chunk[3]);
        }
    }

    #[test]
    fn nv12_roundtrip_black() {
        let mut argb = vec![0u8; 2 * 2 * 4];
        for chunk in argb.chunks_exact_mut(4) {
            chunk[0] = 255;
        }
        let nv12 = argb_to_nv12(&argb, 2, 2);
        let back = nv12_to_argb(&nv12, 2, 2);
        for chunk in back.chunks_exact(4) {
            assert_eq!(chunk[0], 255);
            assert!(chunk[1] < 5, "R should be near 0, got {}", chunk[1]);
            assert!(chunk[2] < 5, "G should be near 0, got {}", chunk[2]);
            assert!(chunk[3] < 5, "B should be near 0, got {}", chunk[3]);
        }
    }
}

//! Aethersafta — Real-time media compositing engine.
//!
//! Multi-source capture, scene graph compositing, hardware-accelerated encoding,
//! and streaming output. Built on [`tarang`] for encoding/muxing,
//! [`ranga`] for image processing, [`dhvani`] for audio capture/mixing/DSP,
//! and [`ai_hwaccel`] for hardware encoder selection.
//!
//! # Architecture
//!
//! ```text
//! Video Sources (screen, camera, media, image)
//!     │
//!     ▼
//! Scene Graph (layers with z-order, transforms, opacity)
//!     │
//!     ▼
//! Compositor (alpha blend, crop, scale → composited frame via ranga)
//!     │
//!     ▼                                    Audio Sources (PipeWire via dhvani)
//! Encode Pipeline                              │
//! (ai-hwaccel → tarang encodes)                ▼
//!     │                                    AudioMixer (per-source DSP, mix, master bus)
//!     ▼                                        │
//! Output Sinks (file, RTMP, SRT) ◄─────────────┘
//! ```
//!
//! # Quick start
//!
//! ```rust,no_run
//! use aethersafta::{SceneGraph, Layer, OutputConfig};
//!
//! // Create a scene with a screen capture source
//! let mut scene = SceneGraph::new(1920, 1080, 30);
//! scene.add_layer(Layer::screen_capture());
//!
//! // Record to file
//! let config = OutputConfig::file("recording.mp4");
//! // scene.start(config)?;
//! ```

pub mod audio;
pub mod encode;
pub mod output;
pub mod scene;
pub mod source;
pub mod timing;

