/// Build a scene graph with a single layer from the --source argument.
fn build_scene(
    source_str: &str,
    width: u32,
    height: u32,
    fps: u32,
) -> anyhow::Result<(SceneGraph, Option<Box<dyn Source>>)> {
    let mut scene = SceneGraph::new(width, height, fps);

    if let Some(path) = source_str.strip_prefix("image:") {
        let src = ImageSource::open(path)?;
        let mut layer = Layer::new(
            src.name(),
            LayerContent::Source {
                source_id: src.id(),
            },
        );
        layer.size = Some((width, height));
        scene.add_layer(layer);
        Ok((scene, Some(Box::new(src))))
    } else if let Some(hex) = source_str.strip_prefix("color:") {
        let color = parse_hex_color(hex)?;
        scene.add_layer(Layer::new("fill", LayerContent::ColorFill { color }));
        Ok((scene, None))
    } else if source_str == "screen" {
        anyhow::bail!("screen capture not yet implemented — use image:<path> or color:<RRGGBBAA>");
    } else {
        anyhow::bail!("unknown source: {source_str}");
    }
}

/// Capture frames from source for all matching layers in the scene.
fn capture_source_frames(
    scene: &SceneGraph,
    source: &Option<Box<dyn Source>>,
) -> HashMap<aethersafta::scene::LayerId, aethersafta::source::RawFrame> {
    let mut frames = HashMap::new();
    if let Some(src) = source {
        for layer in scene.layers() {
            if let LayerContent::Source { source_id } = &layer.content
                && *source_id == src.id()
                && let Ok(Some(f)) = src.capture_frame()
            {
                frames.insert(layer.id, f);
            }
        }
    }
    frames
}

fn parse_hex_color(hex: &str) -> anyhow::Result<[u8; 4]> {
    if hex.len() != 8 {
        anyhow::bail!("color must be 8 hex chars (RRGGBBAA), got: {hex}");
    }
    let r = u8::from_str_radix(&hex[0..2], 16)?;
    let g = u8::from_str_radix(&hex[2..4], 16)?;
    let b = u8::from_str_radix(&hex[4..6], 16)?;
    let a = u8::from_str_radix(&hex[6..8], 16)?;
    Ok([r, g, b, a])
}

/// Set up audio capture via dhvani PipeWire, if requested.
///
/// Returns the audio mixer, capture manager, and source ID.
/// Supports multiple audio sources via `AudioCaptureManager`.
#[cfg(feature = "pipewire")]
fn setup_audio(
    audio_arg: &str,
    gain_db: f32,
) -> anyhow::Result<
    Option<(
        aethersafta::audio::AudioMixer,
        aethersafta::audio::AudioCaptureManager,
        aethersafta::audio::AudioSourceId,
    )>,
> {
    if audio_arg == "none" {
        return Ok(None);
    }

    let device_id = if audio_arg == "default" {
        None
    } else {
        Some(audio_arg.parse::<u32>().map_err(|_| {
            anyhow::anyhow!("--audio must be \"default\", \"none\", or a device ID (integer)")
        })?)
    };

    let mut mixer =
        aethersafta::audio::AudioMixer::new(aethersafta::audio::AudioMixerConfig::default());
    let mut src_config = aethersafta::audio::AudioSourceConfig::new("PipeWire Capture");
    src_config.gain_db = gain_db;
    src_config.device_id = device_id;
    let src_id = mixer.add_source(src_config.clone());

    let mut capture_mgr = aethersafta::audio::AudioCaptureManager::new();
    capture_mgr.add_source(src_id, src_config)?;

    info!(
        "audio capture: PipeWire (device={}, 48kHz stereo)",
        device_id.map_or("default".into(), |id| id.to_string())
    );

    Ok(Some((mixer, capture_mgr, src_id)))
}

#[allow(clippy::too_many_arguments)]
fn cmd_record(
    source_str: &str,
    output_path: &str,
    duration_secs: u64,
    fps: u32,
    width: u32,
    height: u32,
    bitrate: u32,
    audio_arg: &str,
    audio_gain: f32,
) -> anyhow::Result<()> {
    let (scene, source) = build_scene(source_str, width, height, fps)?;
    let compositor = Compositor::new(width, height);
    let mut clock = FrameClock::new(fps);

    let total_frames = if duration_secs == 0 {
        info!("recording until interrupted (Ctrl+C)");
        u64::MAX
    } else {
        let n = duration_secs * fps as u64;
        info!("recording {duration_secs}s ({n} frames) to {output_path}");
        n
    };

    // Init encoder (hw auto-detect via ai-hwaccel, sw fallback)
    let mut encoder = EncodePipeline::new(EncoderConfig {
        codec: VideoCodec::H264,
        bitrate_kbps: bitrate,
        ..Default::default()
    });
    encoder.init(width, height, fps)?;
    info!("encoder: {} @ {bitrate} kbps", encoder.backend());

    // Use MP4 container for .mp4 files, raw bitstream otherwise
    let is_mp4 = output_path.ends_with(".mp4");
    let mut mp4_out = if is_mp4 {
        Some(aethersafta::output::mp4::Mp4Output::create_video_only(
            output_path,
            tarang::core::VideoCodec::H264,
            width,
            height,
        )?)
    } else {
        None
    };
    let mut file_out = if !is_mp4 {
        Some(FileOutput::create(output_path)?)
    } else {
        None
    };
    if is_mp4 {
        info!("output: MP4 container (via tarang muxer)");
    }

    // Audio setup (PipeWire capture → mixer)
    #[cfg(feature = "pipewire")]
    let mut audio_state = setup_audio(audio_arg, audio_gain)?;
    #[cfg(not(feature = "pipewire"))]
    let audio_state: Option<()> = {
        if audio_arg != "none" {
            anyhow::bail!("audio capture requires --features pipewire");
        }
        None
    };

    let start = Instant::now();
    for frame_num in 0..total_frames {
        clock.tick();

        // Video: capture → composite → encode → output
        let frames = capture_source_frames(&scene, &source);
        let composited = compositor.compose(&scene, &frames, clock.current_pts_us());
        let packet = encoder.encode_frame(&composited)?;
        if let Some(ref mut mp4) = mp4_out {
            mp4.write_video(&packet)?;
        } else if let Some(ref mut raw) = file_out {
            raw.write_packet(&packet)?;
        }

        // Audio: drain capture → mix (audio data is collected but not yet muxed
        // into the output file — requires tarang container muxing, tracked in roadmap v0.22.0)
        #[cfg(feature = "pipewire")]
        if let Some((ref mut mixer, ref capture_mgr, _)) = audio_state {
            let mut audio_buffers = capture_mgr.drain_buffers();
            if !audio_buffers.is_empty() {
                let _mixed = mixer.mix(&mut audio_buffers);
                // TODO: mux audio into container via tarang::demux::Mp4Muxer
            }
        }

        if (frame_num + 1) % (fps as u64) == 0 {
            let elapsed = start.elapsed().as_secs_f64();
            let bytes = mp4_out
                .as_ref()
                .map(|m| m.bytes_written())
                .or_else(|| file_out.as_ref().map(|f| f.bytes_written()))
                .unwrap_or(0);

            #[cfg(feature = "pipewire")]
            if let Some((ref mixer, _, _)) = audio_state {
                let [l, r] = [mixer.master_peak_db(0), mixer.master_peak_db(1)];
                info!(
                    "frame {}: {:.1}s, {} bytes, audio L={:.1}dB R={:.1}dB",
                    frame_num + 1,
                    elapsed,
                    bytes,
                    l,
                    r,
                );
            } else {
                info!("frame {}: {:.1}s, {} bytes", frame_num + 1, elapsed, bytes);
            }
            #[cfg(not(feature = "pipewire"))]
            info!("frame {}: {:.1}s, {} bytes", frame_num + 1, elapsed, bytes);
        }
    }

    // Shut down audio capture
    #[cfg(feature = "pipewire")]
    if let Some((_, ref mut capture_mgr, _)) = audio_state {
        capture_mgr.stop_all();
    }

    // Finalize output
    let total_bytes;
    if let Some(ref mut mp4) = mp4_out {
        mp4.finalize()?;
        total_bytes = mp4.bytes_written();
    } else if let Some(ref mut raw) = file_out {
        raw.close()?;
        total_bytes = raw.bytes_written();
    } else {
        total_bytes = 0;
    }
    info!(
        "done: {} frames, {} bytes written to {}",
        encoder.frames_encoded(),
        total_bytes,
        output_path
    );

    Ok(())
}

fn cmd_preview(source_str: &str, fps: u32, max_frames: u64) -> anyhow::Result<()> {
    let width = 1920;
    let height = 1080;
    let (scene, source) = build_scene(source_str, width, height, fps)?;
    let compositor = Compositor::new(width, height);
    let mut clock = FrameClock::new(fps);

    let total = if max_frames == 0 {
        u64::MAX
    } else {
        max_frames
    };

    info!("preview: compositing {fps}fps (no display backend — logging frame stats)");

    let start = Instant::now();
    for frame_num in 0..total {
        clock.tick();

        let frames = capture_source_frames(&scene, &source);

        let composited = compositor.compose(&scene, &frames, clock.current_pts_us());

        if (frame_num + 1) % (fps as u64) == 0 {
            let elapsed = start.elapsed().as_secs_f64();
            let actual_fps = (frame_num + 1) as f64 / elapsed;
            info!(
                "frame {}: pts={}µs, {:.0} fps, behind={}",
                frame_num + 1,
                composited.pts_us,
                actual_fps,
                clock.is_behind()
            );
        }
    }

    let elapsed = start.elapsed();
    info!(
        "preview done: {} frames in {:.2}s ({:.1} fps)",
        total.min(max_frames),
        elapsed.as_secs_f64(),
        total.min(max_frames) as f64 / elapsed.as_secs_f64()
    );

    Ok(())
}

//! File output sink: writes encoded packets to a local file.
//!
//! Currently writes raw H.264 bitstream (`.h264`). MP4 container
//! muxing will be added when tarang supports video muxing.

use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::{Path, PathBuf};

use super::{EncodedPacket, OutputSink};

/// Writes encoded video packets to a file.
///
/// Uses a 256 KB buffer to avoid per-packet syscalls.
pub struct FileOutput {
    path: PathBuf,
    file: BufWriter<File>,
    bytes_written: u64,
    packets_written: u64,
}

impl FileOutput {
    /// Create a new file output sink.
    pub fn create(path: impl AsRef<Path>) -> anyhow::Result<Self> {
        let path = path.as_ref();
        let file = BufWriter::with_capacity(256 * 1024, File::create(path)?);
        Ok(Self {
            path: path.to_path_buf(),
            file,
            bytes_written: 0,
            packets_written: 0,
        })
    }

    /// The output file path.
    #[must_use]
    pub fn path(&self) -> &Path {
        &self.path
    }

    /// Total bytes written.
    #[must_use]
    pub fn bytes_written(&self) -> u64 {
        self.bytes_written
    }

    /// Total packets written.
    #[must_use]
    pub fn packets_written(&self) -> u64 {
        self.packets_written
    }
}

impl OutputSink for FileOutput {
    fn write_packet(&mut self, packet: &EncodedPacket) -> anyhow::Result<()> {
        self.file.write_all(&packet.data)?;
        self.bytes_written += packet.data.len() as u64;
        self.packets_written += 1;
        Ok(())
    }

    fn flush(&mut self) -> anyhow::Result<()> {
        self.file.flush()?;
        Ok(())
    }

    fn close(&mut self) -> anyhow::Result<()> {
        self.file.flush()?;
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn write_and_read_back() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("test.h264");

        let mut out = FileOutput::create(&path).unwrap();
        let packet = EncodedPacket {
            data: vec![0x00, 0x00, 0x00, 0x01, 0x67], // fake NAL unit
            pts_us: 0,
            dts_us: 0,
            is_keyframe: true,
        };
        out.write_packet(&packet).unwrap();
        out.flush().unwrap();

        assert_eq!(out.packets_written(), 1);
        assert_eq!(out.bytes_written(), 5);

        let contents = std::fs::read(&path).unwrap();
        assert_eq!(contents, vec![0x00, 0x00, 0x00, 0x01, 0x67]);
    }

    #[test]
    fn multiple_packets() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("multi.h264");

        let mut out = FileOutput::create(&path).unwrap();
        for i in 0..5 {
            out.write_packet(&EncodedPacket {
                data: vec![i as u8; 10],
                pts_us: i * 33000,
                dts_us: i * 33000,
                is_keyframe: i == 0,
            })
            .unwrap();
        }
        out.close().unwrap();

        assert_eq!(out.packets_written(), 5);
        assert_eq!(out.bytes_written(), 50);
    }
}

//! Output sinks: file recording, RTMP streaming, SRT streaming.

pub mod file;
pub mod mp4;

use serde::{Deserialize, Serialize};

/// An encoded packet ready for output.
#[derive(Debug, Clone)]
pub struct EncodedPacket {
    /// Compressed data.
    pub data: Vec<u8>,
    /// Presentation timestamp in microseconds.
    pub pts_us: u64,
    /// Decode timestamp in microseconds.
    pub dts_us: u64,
    /// Whether this is a keyframe.
    pub is_keyframe: bool,
}

/// Output configuration.
#[non_exhaustive]
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum OutputConfig {
    /// Record to a local file.
    File { path: String },
    /// Stream via RTMP.
    Rtmp { url: String, stream_key: String },
    /// Stream via SRT.
    Srt {
        address: String,
        passphrase: Option<String>,
    },
}

impl OutputConfig {
    /// Convenience: file output.
    #[must_use]
    pub fn file(path: impl Into<String>) -> Self {
        Self::File { path: path.into() }
    }

    /// Convenience: RTMP output.
    #[must_use]
    pub fn rtmp(url: impl Into<String>, key: impl Into<String>) -> Self {
        Self::Rtmp {
            url: url.into(),
            stream_key: key.into(),
        }
    }
}

/// The `OutputSink` trait: anything that can consume encoded packets.
pub trait OutputSink: Send + Sync {
    /// Write an encoded packet to the output.
    fn write_packet(&mut self, packet: &EncodedPacket) -> anyhow::Result<()>;

    /// Flush buffered data.
    fn flush(&mut self) -> anyhow::Result<()>;

    /// Close the output and finalize (e.g. write container trailer).
    fn close(&mut self) -> anyhow::Result<()>;
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn output_config_file() {
        let cfg = OutputConfig::file("test.mp4");
        match cfg {
            OutputConfig::File { path } => assert_eq!(path, "test.mp4"),
            _ => panic!("expected File"),
        }
    }

    #[test]
    fn output_config_rtmp() {
        let cfg = OutputConfig::rtmp("rtmp://live.twitch.tv/app", "my_key");
        match cfg {
            OutputConfig::Rtmp { url, stream_key } => {
                assert!(url.contains("twitch"));
                assert_eq!(stream_key, "my_key");
            }
            _ => panic!("expected Rtmp"),
        }
    }

    #[test]
    fn serde_roundtrip() {
        let cfg = OutputConfig::Srt {
            address: "srt://host:9000".into(),
            passphrase: Some("secret".into()),
        };
        let json = serde_json::to_string(&cfg).unwrap();
        let back: OutputConfig = serde_json::from_str(&json).unwrap();
        match back {
            OutputConfig::Srt {
                address,
                passphrase,
            } => {
                assert!(address.contains("9000"));
                assert_eq!(passphrase.unwrap(), "secret");
            }
            _ => panic!("expected Srt"),
        }
    }
}

//! MP4 container output via tarang's muxer.
//!
//! Writes encoded video (and optionally audio) into a proper MP4 container
//! instead of a raw bitstream. Supports video-only or audio+video modes.

use std::fs::File;
use std::path::{Path, PathBuf};

use tarang::demux::{Mp4Muxer, MuxConfig, Muxer, VideoMuxConfig};

use super::EncodedPacket;

/// Writes encoded video packets into an MP4 container.
pub struct Mp4Output {
    path: PathBuf,
    muxer: Mp4Muxer<File>,
    packets_written: u64,
    bytes_written: u64,
    finalized: bool,
}

impl Mp4Output {
    /// Create a video-only MP4 output.
    pub fn create_video_only(
        path: impl AsRef<Path>,
        codec: tarang::core::VideoCodec,
        width: u32,
        height: u32,
    ) -> anyhow::Result<Self> {
        let path = path.as_ref();
        let file = File::create(path)?;
        let video_config = VideoMuxConfig {
            codec,
            width,
            height,
        };
        // tarang 0.20.3 requires audio config; use dummy config for video-only.
        let audio_config = MuxConfig {
            codec: tarang::core::AudioCodec::Aac,
            sample_rate: 48000,
            channels: 2,
            bits_per_sample: 16,
        };
        let mut muxer = Mp4Muxer::new_with_video(file, audio_config, video_config);
        muxer.write_header()?;

        Ok(Self {
            path: path.to_path_buf(),
            muxer,
            packets_written: 0,
            bytes_written: 0,
            finalized: false,
        })
    }

    /// Create an audio+video MP4 output.
    pub fn create_with_audio(
        path: impl AsRef<Path>,
        video_codec: tarang::core::VideoCodec,
        width: u32,
        height: u32,
        audio_config: MuxConfig,
    ) -> anyhow::Result<Self> {
        let path = path.as_ref();
        let file = File::create(path)?;
        let video_config = VideoMuxConfig {
            codec: video_codec,
            width,
            height,
        };
        let mut muxer = Mp4Muxer::new_with_video(file, audio_config, video_config);
        muxer.write_header()?;

        Ok(Self {
            path: path.to_path_buf(),
            muxer,
            packets_written: 0,
            bytes_written: 0,
            finalized: false,
        })
    }

    /// Write a video packet to the MP4 container.
    pub fn write_video(&mut self, packet: &EncodedPacket) -> anyhow::Result<()> {
        self.muxer.write_video_packet(&packet.data)?;
        self.packets_written += 1;
        self.bytes_written += packet.data.len() as u64;
        Ok(())
    }

    /// Write an audio packet to the MP4 container.
    pub fn write_audio(&mut self, data: &[u8]) -> anyhow::Result<()> {
        self.muxer.write_packet(data)?;
        self.bytes_written += data.len() as u64;
        Ok(())
    }

    /// Finalize the MP4 container (write moov atom, fix headers).
    pub fn finalize(&mut self) -> anyhow::Result<()> {
        if !self.finalized {
            self.muxer.finalize()?;
            self.finalized = true;
        }
        Ok(())
    }

    /// The output file path.
    #[must_use]
    pub fn path(&self) -> &Path {
        &self.path
    }

    /// Total video packets written.
    #[must_use]
    pub fn packets_written(&self) -> u64 {
        self.packets_written
    }

    /// Total bytes written to the container.
    #[must_use]
    pub fn bytes_written(&self) -> u64 {
        self.bytes_written
    }
}

impl Drop for Mp4Output {
    fn drop(&mut self) {
        if !self.finalized {
            // Best-effort finalize to prevent corrupt MP4 files.
            let _ = self.muxer.finalize();
        }
    }
}

