        };
        assert!(!frame.is_valid());
    }

    #[test]
    fn nv12_expected_size() {
        // 1920x1080 NV12: Y=1920*1080 + UV=1920*540 = 2073600 + 1036800 = 3110400
        assert_eq!(
            RawFrame::expected_size_for(PixelFormat::Nv12, 1920, 1080),
            1920 * 1080 + 1920 * 540
        );
    }

    #[test]
    fn nv12_frame_valid() {
