        let r = chunk[1];
        let g = chunk[2];
        let b = chunk[3];
        assert!(r > 110 && r < 145, "R={r}, expected near 127");
        assert!(g > 110 && g < 145, "G={g}, expected near 127");
        assert!(b < 15, "B={b}, expected near 0");
    }
}

